@ARTICLE{10.1093/ehjcr/ytag092,
	author = {Salinas-Gonzalez R, López MC, Bolaños C and Lavilla MÁC, de la Garza MS},
	title = {A multicomponent cardiac rehabilitation programme as a safe, feasible, and beneficial approach, including patients with left ventricular assist devices: a case report.},
	journal = {Eur Heart J Case Rep},
	year = {2026},
	abstract = {BACKGROUND: Left ventricular assist devices (LVADs) are a well-established therapy for advanced heart failure (HF) used either as a bridge-to-transplant or destination therapy. While cardiac rehabilitation programmes (CRPs) are guideline-recommended in other HF stages, specific data on their role in LVAD recipients remains limited. We present a case of tailored CRP in a LVAD-supported patient highlighting the importance of understanding the device's intrinsic limitations to ensure safe and effective exercise prescription. CASE SUMMARY: A 56-year-old man with cardiovascular risk factors presented with anterior ST-elevation myocardial infarction developing severe left ventricular dysfunction, INTERMACS III, and recurrent ventricular arrhythmias, leading to HeartMate 3 (HM3) LVAD implantation as a bridge-to-transplant. Persistent smoking led to discontinuation of prehabilitation and removal from the transplant waitlist. A destination therapy strategy was considered and referred to the CRP. Baseline and final assessments included a CPET-ESE, clinical-functional evaluation, and PROMs. The rehabilitation physician, as part of the multidisciplinary team, adapted the exercise prescription to manage neuropathic pain due to a suspected spinal cord injury. Doppler-MAP and HM3 LVAD parameters were monitored before and after each session. The patient completed a tailored 12-week CRP with high adherence and no major adverse events. Improvements were observed in submaximal CPET parameters: VO2 at VT1, OUES and VE/VCO2 slope, right ventricle contractility, muscular efficiency, and QoL. Persistent smoking remained the main management challenge. DISCUSSION: Tailored CRP with careful haemodynamic monitoring is safe, feasible, and effective in patients with HM3 LVAD. A multidisciplinary approach is essential to optimize functional outcomes and long-term prognosis.},
	doi = {10.1093/ehjcr/ytag092},
	pmid = {41907868},
	note = {PMC13019305}
}

@ARTICLE{10.1016/j.ahjo.2026.100752,
	author = {Hendricks E and Calkins T and Cohen T and Parker AM and Vilaro JR and Aranda JM Jr and Ahmed MM},
	title = {Ultraslow deflation automated sphygmomanometry in continuous-flow-left ventricular assist device patients.},
	journal = {Am Heart J Plus},
	year = {2026},
	abstract = {INTRODUCTION: Left ventricular assist device (LVAD) is indicated for short- and long-term mechanical circulatory support. As hypertension is a risk factor for complications and unfavorable outcomes in LVAD recipients, blood pressure (BP) control is essential. Accurate measurement of BP can be challenging, as the degree of pulsatility and aortic valve opening can vary between patients. The ultraslow deflation automated sphygmomanometer, designed for those with a weak pulse and whose cuff deflation algorithm allows for the detection of a narrower pulse pressure, may be useful for accurate and simple BP measurement in continuous-flow-LVAD patients. METHODS: This pilot study assessed the accuracy and ease of use of the ultraslow deflation automated sphygmomanometer in both the in-patient and ambulatory clinical settings. Seven consecutive in-patients had arterial line monitoring and a HeartMate 3 (HM3) LVAD. All patients underwent 3 BP measurements with each modality at 3 separate times. In the outpatient setting, 11 consecutive patients (9 HM3 and 2 HeartWare HVAD) had mean arterial pressure (MAP) measurement using both Doppler RTF and ultraslow deflation automated sphygmomanometer. RESULTS: There was no difference in mean MAP for each in-patient between modalities and across all patients based on BP measurement modality. In outpatients, there was no significant difference in MAP within each patient across modalities or users. CONCLUSION: Ultraslow deflating sphygmomanometer appears to be reliable, accurate, and easy to use for BP monitoring in LVAD patients and may represent a more accessible and patient friendly method for BP management.},
	doi = {10.1016/j.ahjo.2026.100752},
	pmid = {41868436},
	note = {PMC13000481}
}

@ARTICLE{10.1016/j.mcpro.2026.101510,
	author = {Mulvey JF and Sailer C and Achter JS and Milburn GN and Bretherton RC and Kahnert K and Erbil Bilir S and Hvid H and Pyke C and Gustafsson F and Adamo L and Campbell KS and Herum KM and Lundby A},
	title = {An Unbiased Molecular Characterization of Peripartum Cardiomyopathy Hearts Identifies Mast Cell Chymase as a New Diagnostic Candidate.},
	journal = {Mol Cell Proteomics},
	year = {2026},
	abstract = {Peripartum cardiomyopathy (PPCM) is a rare form of acute heart failure that develops in women toward the end of pregnancy or early postpartum. No effective, specific treatment for PPCM is available and heart transplantation or mechanical circulatory support may be required in severe cases where drug treatment for heart failure is insufficient. The mechanisms through which the disease progresses are not well understood, and despite similar clinical characteristics to dilated cardiomyopathy of other etiologies (nonperipartum cardiomyopathy; NPCM) it is not known how the molecular remodeling differs between these groups. We aimed to provide insight into the human PPCM heart using unbiased methodologies, and to use changes occurring within the heart tissue to facilitate biomarker discovery. We obtained heart tissue from female patients with end-stage disease receiving either heart transplantation or left ventricular assist device implantation, or from organ donors without heart disease as a control group. We performed deep proteomics, single nucleus transcriptomics and spatial transcriptomics, providing a comprehensive map of the molecular phenotype in advanced PPCM compared to both control and NPCM hearts. Consistent with similarities in the clinical phenotypes of PPCM and NPCM, we observed regulation of canonical markers of end-stage heart failure in both PPCM and NPCM hearts in comparison to controls. Among the changes specific to PPCM and that were consistently observed across multiple data types and cohorts was an upregulation of chymase and carboxypeptidase A3, consistent with mast cell proliferation/activation. Analysis of the proteome of peripheral blood serum from a larger cohort of patients with PPCM and controls showed that chymase was strongly predictive of cardiomyopathy in peripartum women. PPCM heart tissue is characterized by increased mast cell proteins chymase and carboxypeptidase A3. Chymase may have clinical utility as a biomarker for the diagnosis of cardiomyopathy in peripartum women.},
	doi = {10.1016/j.mcpro.2026.101510},
	pmid = {41539643 [Indexed for MEDLINE]},
	note = {PMC12906182}
}

@ARTICLE{10.1097/MAT.0000000000002631,
	author = {Rajendra S and Salmasi Y and Raj B and Dar O and Marczin N and Francis D and Khoshbin E},
	title = {Perioperative Predictors of Right Ventricular Failure Following Left Ventricular Assist Device Implantation.},
	journal = {ASAIO J},
	year = {2025},
	abstract = {Right ventricular failure (RVF) is an important complication following implantation of a left ventricular assist device (LVAD) in patients with advanced heart failure. This study aims to identify perioperative hemodynamic predictors of RVF following LVAD implantation and develop an internally validated predictive model. Patients who underwent LVAD implantations between March 2013 and March 2023 at a large-volume tertiary center were retrospectively analyzed. The primary outcome was early post-implant RVF, defined by need for right ventricular assist device (RVAD), prolonged inotrope dependence (> 14 days), or death within 14 days while on inotropes. Perioperative hemodynamic variables were analyzed using univariate logistic regression. A prediction model was then developed using stepwise multivariate logistic regression, and internally validated using k-fold cross-validation. Among 210 patients, 73 patients (34.8%) developed early post-implant RVF. Decreased post-implant cardiac index (odds ratio [OR]: 0.0122, p = 0.001), decreased mean arterial pressure (OR: 0.932, p = 0.008), and simultaneously increased cardiac index and pulmonary pulse pressure (OR: 1.13, p = 0.021) independently predicted RVF. Preimplantation IV inotrope therapy was a significant confounder (OR: 3.96, p = 0.021). Our proposed predictive model achieved strong discriminatory power (area under the curve [AUC] of 0.830) and stable cross-validation performance. External validation with multicenter cohorts is warranted to confirm predictive accuracy and clinical applicability.},
	doi = {10.1097/MAT.0000000000002631},
	pmid = {41430755}
}

@ARTICLE{10.1016/j.jjcc.2025.11.015,
	author = {Lin E and Bilchick K and Mehta N and Kwon Y and Ilonze O and Breathett K and Phiri J and Ernest R and Vidic A and Kabwe J and Bolaji O and Bandaru J and Mubanga M and Krittanawong C and Ashur N and Mazimba S},
	title = {Trajectories in renal perfusion pressure during hemodynamically guided therapy are associated with worsening renal function and patient outcomes.},
	journal = {J Cardiol},
	year = {2026},
	abstract = {BACKGROUND: Worsening renal function (WRF) during acute decompensated heart failure (ADHF) therapy portends worse outcomes. We hypothesized that renal perfusion pressure (RPP), systemic mean arterial pressure minus central venous pressure (CVP), is associated with and may elucidate mechanisms of WRF. We theorized that machine learning-based RPP trajectories could impact outcomes. METHODS: Patients in the Evaluation Study of Congestive Heart Failure and Pulmonary Artery Catheterization (PAC) Effectiveness (ESCAPE) Trial randomized to PAC-guided therapy were evaluated. M-estimation, logistic regression, and receiver operating characteristic analysis were performed. Trajectories were analyzed by selecting summary measures capturing the most variance in the trajectories using factor analysis and applying clustering with the k-means methods based on these summary measures. RESULTS: Among 143 patients (age 56.7 ± 13.8 years, 26.6 % female), 17 patients (11.9 %) had >30 % decrease in glomerular filtration rate (GFR) during therapy. Percent change in GFR (%∆GFR) was positively associated with percent change in RPP (%∆RPP) (M-estimation coefficient 0.248; p = 0.02). %∆GFR was associated with %∆RPP, controlling for body mass index and ischemic cardiomyopathy (M-estimation coefficients 0.22, -0.007, and - 0.109; p = 0.033). RPP trajectories were associated with overall survival [OS; Kaplan-Meier (KM) p < 0.001] and survival free of transplant, left ventricular assist device, and heart failure hospitalization (HFH, KM p = 0.002). Favorable RPP trajectory was associated with improved outcomes, even with elevated creatinine (OS: KM p < 0.001, HFH: KM p < 0.001). Mediation effect of CVP at discharge was 10.4 % and 10 % for baseline creatinine. CONCLUSIONS: RPP changes potentially explain a mechanism of WRF in patients undergoing PAC-guided therapy for ADHF. Trajectories of RPP predict survival and hospitalization outcomes and could improve nuanced risk stratification of cardiorenal syndromes in patients with ADHF.},
	doi = {10.1016/j.jjcc.2025.11.015},
	pmid = {41349944 [Indexed for MEDLINE]}
}

@ARTICLE{10.1053/j.jvca.2025.09.035,
	author = {Emery DA and Ciapala S and Williams JB and Bhattacharya S and Higgins A and Lee R and Bhat P and Soltesz E and Tong MZ and Hohlfelder B},
	title = {Outcomes and Risk Factors in Vasoplegic Patients Following Left Ventricular Assist Device Implantation.},
	journal = {J Cardiothorac Vasc Anesth},
	year = {2026},
	abstract = {OBJECTIVE: To describe vasoplegia incidence, management strategies, and factors associated with vasoplegia in a HeartMate left ventricular assist device (LVAD) patient population. DESIGN: A retrospective, observational study was performed. The primary outcome was the incidence of vasoplegia (persistent hypotension requiring >0.2 μg/kg/min norepinephrine equivalent for >6 hours) following LVAD implantation. Multivariable logistic regression analysis was conducted to determine factors associated with the development of vasoplegia. A subgroup analysis was performed to compare patients who received and did not receive preoperative renin-angiotensin-aldosterone system inhibitors to evaluate their impact on postoperative vasoplegia. SETTING: A single-center, quaternary care academic medical center. PARTICIPANTS: Adult patients (N = 184) who will undergo LVAD implantation from 2019 to 2022. INTERVENTIONS: None. MEASUREMENTS AND MAIN RESULTS: The incidence of vasoplegia was 33%. In patients who developed vasoplegia, the median maximum dosage of vasopressors was 0.28 μg/kg/min (0.24-0.34) norepinephrine equivalents with a median duration of 30 hours (18-50) on vasopressors. Mean arterial pressure immediately before the operating room (OR 0.961), duration on cardiopulmonary bypass (OR 1.012), preoperative renal dysfunction (OR 3.185), and postoperative inotrope use (OR 4.857) were independently associated with risk of vasoplegia based on multivariable logistic regression analysis. No differences in rates of vasoplegia were observed based on receipt of preoperative renin-angiotensin-aldosterone system inhibitors. No mortality differences were observed between patients who did versus did not develop vasoplegia. CONCLUSIONS: Vasoplegia following LVAD implantation is a common postoperative complication. Longer duration on cardiopulmonary bypass, preoperative renal dysfunction, and postoperative inotrope use following LVAD implantation were associated with an increased risk of developing postoperative vasoplegia.},
	doi = {10.1053/j.jvca.2025.09.035},
	pmid = {41111020 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/ehf2.15410,
	author = {Knigge S and Bastos MB and Schmack B and Schana L and Malchin O and Merzah AS and Popov AF and Weymann A and Ruhparwar A and Schumacher F and Dogan G and Schmitto JD},
	title = {First evaluation of a novel pulsatile LVAD: Feasibility and haemodynamic impact in acute heart failure.},
	abstract = {AIMS: Non-pharmacological therapies for acute decompensated heart failure (HF) and cardiogenic shock have evolved considerably in recent decades. Short-term mechanical circulatory support (MCS) devices can be used as circulatory backup. While nearly all available devices use continuous flow, evidence indicates that pulsatile flow can be more effective. This study presents the first experimental use of a novel counter-pulsatile left ventricular (LV) assist device (LVAD) with a primary focus on assessing its feasibility and effectiveness. METHODS: The pulsatile ventricular assist platform (pVAP) was applied in six porcine models of acute ischaemic HF with the inlet in the left atrium and the outlet in the aorta. HF was induced through stepwise ligation of the left anterior descending artery and its diagonal branches. The pVAP functioned driven by a conventional IABP console while LV pressure-volume (PV) loops and standard haemodynamics with the device OFF and ON were recorded. Absolute values and percent variations were compared using Mann-Whitney's U test and Wilcoxon's sign-rank test. RESULTS: The device's output flow is frequency dependent, with an output flow of 2.64 ± 0.22 L/min at 80 bpm. Activation reduced the EDV [132 (90-145) vs. 118 (83-130) mL, P < 0.05], EDP 9 (6-10) vs. 6 (5-9) mmHg, P < 0.001], native cardiac output [CON, 3.64 (2.88-6.71) vs. 1.67 (1.24-2.48) L/min, P < 0.001] and myocardial oxygen consumption [pressure-volume area * heart rate (PVA*HR), 4592 (2944-9272) vs. 2901 (1915-4437) mJ, P < 0.001]. Contractility decreased, with right-shifting the end-systolic PV relationship (ESPVR) while ESP and forward cardiac output COF were constant. The mean arterial pressure increased [54 (48-60) vs. 49 (42-55) mmHg, P < 0.001] and mPAP decreased [10 (8-11) to 9 (7-10) mmHg, P < 0.01]. The PV loop shifted left and downward. No changes occurred in the passive-elastic properties of the LV in diastole. CONCLUSIONS: The pVAP reduced the LV mechanical load while increasing systemic pressures and reducing pulmonary pressures. Its functionality as an LVAD is characterised by consistent and predictable performance. Further research is necessary to elucidate the physiological and clinical impact of the device in animals and, subsequently, in humans.},
	doi = {10.1002/ehf2.15410},
	pmid = {40923678 [Indexed for MEDLINE]},
	note = {PMC12719851}
}

@ARTICLE{10.1016/j.jchf.2025.102657,
	author = {Cikes M and Brugts JJ and Claggett B and Jorde UP and Milicic D and Planinc I and Ruschitzka F and Uriel N and Kulac I and Jakus N and Loncaric F and Puskaric F and Sipus D and Gasparovic H and Rubis P, van Laake LW and Rudez I and Hegarova M and Sestan G and Wisniowska-Smialek S and Wierzbicki K and Mehra MR and Solomon SD},
	title = {Angiotensin-Neprilysin Inhibition and Left Ventricular Assist Device Therapy: Primary Results of the ENVAD-HF Trial.},
	journal = {JACC Heart Fail},
	year = {2025},
	abstract = {BACKGROUND: The role of heart failure-specific therapies in left ventricular assist device (LVAD) recipients is unclear, and observational data suggest improved outcomes with neurohormonal blockers. OBJECTIVES: ENVAD-HF (Multicenter, Randomized, Open-Label, Parallel Group, Study to Evaluate the Use of Sacubitril/Valsartan in HeartMate 3 LVAD Recipients) sought to evaluate the safety and tolerability of the angiotensin-neprilysin inhibitor sacubitril/valsartan vs standard of care (SOC) for managing blood pressure (BP) in HeartMate 3 LVAD recipients. METHODS: ENVAD-HF was a prospective multicenter, randomized, open-label study of sacubitril/valsartan vs SOC for managing BP (mean arterial pressure goal: 75-90 mm Hg) in stable LVAD recipients with 12-month follow-up. The composite primary endpoint was time to death, deterioration in renal function, hyperkalemia, or symptomatic hypotension leading to drug withdrawal. Exploratory endpoints included clinical and biomarker assessments and patient-reported outcomes. RESULTS: In 60 randomized patients (30 in each arm), sacubitril/valsartan compared with SOC demonstrated an HR of 0.42 (95% CI: 0.08-2.18; P = 0.30) for the primary endpoint at 12 months. Two primary endpoints were reached in the sacubitril/valsartan group (1 death and 1 symptomatic hypotension event) compared with 5 in the SOC group (2 deaths, 2 worsening renal function events, and 1 symptomatic hypotension event). Numerical trends in favor of sacubitril/valsartan were noted for other exploratory endpoints, including a reduced number of BP medications (difference: -1.09 [95% CI: -1.52 to -0.66]; P < 0.0001) and a significantly better Kansas City Cardiomyopathy Questionnaire-Overall Summary Score (improvement: +10.6 [95% CI: 2.6-18.7]; P = 0.011). CONCLUSIONS: ENVAD-HF, a prospective randomized controlled trial of angiotensin-neprilysin inhibition in stable HeartMate 3 LVAD recipients, demonstrated the safety and tolerability of this therapy in this unique population. The trial forms the basis for a pivotal trial to investigate the usefulness of HF-specific therapies in the LVAD population. (Sacubitril/Valsartan in Left Ventricular Assist Device Recipients [ENVAD-HF], NCT04103554; A multicENter, randomized, open-label, parallel group, pilot study to evaluate the use of sacubitril/valsartan in HeartMate 3 LVAD recipients, 2019-003888-22).},
	doi = {10.1016/j.jchf.2025.102657},
	pmid = {40892548 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.cardfail.2025.07.015,
	author = {Cikes M and Planinc I and Brugts JJ and Claggett B and Jorde UP and Milicic D and Ruschitzka F and Uriel N and Jakus N and Loncaric F and Puskaric F and Rubis P, van Laake LW and Rudez I and Hegarova M and Mehra M and Solomon SD},
	title = {Rationale, design, and baseline characteristics of the multicENter, randomized, open-label, parallel group, study to evaluate the use of sacubitril/valsartan in HeartMate 3 left ventricular assist device recipients (ENVAD-HF).},
	journal = {J Card Fail},
	year = {2026},
	abstract = {BACKGROUND: With notable improvements in long-term survival and hemocompatibility-related events, heart failure (HF) is emerging as a leading cause of death in the contemporary left ventricular assist device (LVAD) population. Although prospective randomized controlled trials have not investigated the use of HF therapies in recipients of LVAD, observational data suggest benefits of neurohormonal blockers, especially in achieving blood pressure (BP) targets associated with improved outcomes. METHODS: The study "multicENter, randomized, open-label, parallel group, pilot study to evaluate the use of sacubitril/valsartan in HeartMate 3 LVAD recipients" (ENVAD-HF) is an investigator-initiated prospective multicenter, randomized, open-label, parallel group, pilot study of recipients of HeartMate 3 (HM3) LVADs to evaluate the safety and tolerability and insights on efficacy of sacubitril/valsartan compared to standard of care (SOC) for managing BP. Medically stable recipients of LVADs after a recent HM3 implantation or in ambulatory follow-up were eligible for participation and randomized 1:1 to receive sacubitril/valsartan or SOC used for treating BP, both titrated aiming for a mean arterial pressure goal 75-90 mm Hg over a 12-month follow-up. The primary endpoint, designed to assess the safety and efficacy of sacubitril/valsartan compared with SOC, is a composite of freedom from all-cause death, deterioration in renal function, hyperkalemia, or symptomatic hypotension. The occurrence of the primary endpoint will be assessed in the first three months and during the overall duration of the trial (12 months). Other endpoints include clinical and patient-reported outcomes, biomarker, and echocardiography assessments during follow-up. RESULTS: ENVAD-HF enrolled 60 patients between February 2021 and March 2024: 17% were female, mean age was 57 ± 12 years, 67% were in ambulatory follow-up, 55% had ischemic etiology, and 25% were receiving an LVAD as destination therapy, with mean baseline mean arterial pressure 87 ± 7 mm Hg and median N-terminal pro B-type natriuretic peptide 2552 (1595-3543) pg/mL. CONCLUSION: ENVAD-HF is the first prospective randomized controlled trial of pharmacologic therapy for the management of BP in stable recipients with HM3 LVADs achieving target enrollment. It will provide data on safety, tolerability, and insights on efficacy of sacubitril/valsartan versus SOC used for treating BP.},
	doi = {10.1016/j.cardfail.2025.07.015},
	pmid = {40818766 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.tvir.2025.101039,
	author = {Verma N and Kondoor V and Singh R and Ahuja R},
	title = {Acute RV Failure Management in Pulmonary Embolism.},
	journal = {Tech Vasc Interv Radiol},
	year = {2025},
	abstract = {Acute right ventricular (RV) failure significantly influences mortality rates in patients experiencing pulmonary embolism (PE). This condition arises from an abrupt increase in RV afterload triggered by clot burden, neurohormonal activation, and hypoxia-mediated feedback mechanisms. The ensuing pathological cascade results in RV dilation, decreased stroke volume, and compromised left ventricular (LV) filling due to interventricular dependence, which can lead to hemodynamic collapse. This paper elucidates management strategies focusing on preload optimization, early clot removal through thrombolytic therapy or thrombectomy, and the judicious use of vasopressors and inotropes to sustain systemic blood pressure, enhance coronary perfusion, and maintain RV-LV coupling. In cases of respiratory failure, mechanical ventilation must be utilized with caution. At the same time, advanced interventions such as extracorporeal membrane oxygenation (ECMO) or RV assist devices are reserved for more severe scenarios. A comprehensive understanding of RV physiology and the pathophysiology of PE is essential for devising early interventions aimed at averting the "RV death spiral" and enhancing patient outcomes. Timely recognition and aggressive management are foundational to treating acute RV failure in PE effectively. Acute right ventricular failure is a critical pathology observed in patients suffering from pulmonary embolism. The significance of understanding the underlying mechanisms of RV failure, particularly concerning PE, cannot be overstated, as it is a crucial determinant of morbidity and mortality. The development of acute RV failure is primarily precipitated by a sudden escalation in RV afterload, a consequence of the obstruction of pulmonary arteries by embolic material. This obstruction induces neurohormonal activation and triggers feedback mechanisms associated with hypoxia, leading to the aforementioned detrimental cascade. The resultant RV dilation and diminished stroke volume adversely affect LV filling due to the phenomenon of interventricular dependence, ultimately paving the way for hemodynamic instability. A nuanced understanding of RV physiology alongside the pathophysiological mechanisms underlying pulmonary embolism is imperative for developing and implementing timely interventions. Early recognition and an aggressive management approach are vital to prevent the "RV death spiral" and improve clinical outcomes for patients confronting acute RV failure in the context of pulmonary embolism.},
	doi = {10.1016/j.tvir.2025.101039},
	pmid = {40634052 [Indexed for MEDLINE]}
}

@ARTICLE{10.1038/s41598-025-06457-0,
	author = {Yastrebov K and Paterson HS and Tian DH and Brunel LM and Schnitzler FC and Partel LM and Dennis M and Bannon PG},
	title = {Head-to-head comparison of V-A ECMO, Impella and ECPELLA in normal ovine hearts.},
	journal = {Sci Rep},
	year = {2025},
	abstract = {Temporary mechanical circulatory support (MCS), including veno-arterial extracorporeal membrane oxygenation (ECMO) and micro-axial pumps (Impella), is increasingly used in clinical practice for refractory circulatory failure. Complex physiological responses to each technique or their combination (ECPELLA) remain debated and are often specific to cardiovascular pathology. A paucity of data on physiological responses to MCS in normal subjects makes comprehensive understanding of such responses in variable disease states difficult, as well as during weaning MCS in recovering hearts. This translational investigation compared three MCS techniques with variable pump flows in healthy sheep (n = 7) to establish baseline for future studies in cardiomyopathic models. All MCS techniques increased arterial elastance, but reduced LV myocardial work, coronary arterial flow and LV myocardial oxygen consumption. ECPELLA was more effective in increasing total systemic blood flow and MAP. The overall similarity between the MCS techniques suggests that the more invasive and complex combination of devices (ECPELLA) can only be justified for management of the severe failing heart as the means for decompressing LV. A study investigating the comparative impacts of different regimes and MCS techniques in a cardiomyopathic model is warranted.},
	doi = {10.1038/s41598-025-06457-0},
	pmid = {40594422 [Indexed for MEDLINE]},
	note = {PMC12215061}
}

@ARTICLE{10.1161/JAHA.125.042249,
	author = {Ikeda Y and Saku K and Nakata J and Unoki T and Yamamoto T and Sakamoto T and Ako J; UNLOADERS‐PVAD Investigators},
	title = {Phase-Specific Hemodynamic Criteria and Outcomes in Patients With Cardiogenic Shock Receiving Percutaneous Ventricular Assist Devices.},
	journal = {J Am Heart Assoc},
	year = {2025},
	abstract = {BACKGROUND: Standardized protocols with optimal hemodynamic targets for percutaneous ventricular assist device (PVAD) management remain undefined. We aimed to evaluate the proportion of phase-specific hemodynamic criteria achieved during PVAD support and their association with outcomes in patients with cardiogenic shock. METHODS: This multicenter retrospective study enrolled patients with cardiogenic shock requiring PVAD (Impella). Patients were evaluated at 24 hours post-PVAD, venoarterial extracorporeal membrane oxygenation weaning, and PVAD weaning. Hemodynamic criteria consisted of key targets, including mean arterial pressure ≥60 mm Hg, lactate <2.0 mmol/L, right atrial pressure <15 mm Hg, pulmonary artery wedge pressure <20 mm Hg, pulmonary artery pulsatility index ≥1.0, and cardiac power output ≥0.6 W. The primary outcome was a composite of 30-day all-cause mortality and unplanned mechanical circulatory support reintroduction. RESULTS: A total of 501 patients were enrolled: 206 (41%) with PVAD alone and 295 (59%) with PVAD and venoarterial extracorporeal membrane oxygenation. The majority of patients were supported with Impella CP (406, 81%). Fulfillment of criteria was observed in 37%, 52%, and 45% at 24 hours post-PVAD, venoarterial extracorporeal membrane oxygenation weaning, and PVAD weaning, respectively. Patients with unfulfilled criteria at each evaluation point were at high risk for the primary outcome (hazard ratio, 3.2 [95% CI, 2.1-4.8]; hazard ratio, 2.1 [1.2-3.7]; and hazard ratio, 2.0 [95% CI, 1.1-3.6]). Hemodynamic criteria achievement consistently stratified the risk of the primary outcome across different subgroups, including shock cause, shock stage, and concomitant use of venoarterial extracorporeal membrane oxygenation. CONCLUSIONS: Phase-specific hemodynamic criteria are often unmet and are associated with significantly higher risks of short-term fatal events.},
	doi = {10.1161/JAHA.125.042249},
	pmid = {40530483 [Indexed for MEDLINE]},
	note = {PMC12449947}
}

@ARTICLE{10.1097/MCC.0000000000001283,
	author = {Baldetti L and Cianfanelli L and Scandroglio AM},
	title = {The intra-aortic balloon pump: a modern practical perspective.},
	journal = {Curr Opin Crit Care},
	year = {2025},
	abstract = {PURPOSE OF REVIEW: After more than 50 years from its invention, the intra-aortic balloon pump (IABP) is still one of the most widely used mechanical circulatory support devices to treat cardiogenic shock (CS). This review aims to describe the role of IABP in current clinical practice. RECENT FINDINGS: In recent years the better understanding of the variable hemodynamic profiles that characterize the CS condition has led to a reappraisal of the IABP role in select CS phenotypes. Combining a "mechanical" afterload reduction with an increase in mean arterial pressure, this device appears particularly suited to treat acute decompensated heart failure-CS and the mechanical complications of an acute myocardial infarction, as these conditions would greatly benefit from systemic afterload reduction. Notwithstanding the negative results of IABP support for acute myocardial infarction-related CS, this document reviews other potential established and emerging settings of application. SUMMARY: In this scoping review, we discuss the IABP design and hemodynamic effects, with a pathophysiology-oriented outlook to its clinical use. Different options for IABP device insertion, potential complications, and optimal device synchronization with cardiac cycle are also summarized with the aim to provide an updated, pragmatic guide to critical care physicians using these devices.},
	doi = {10.1097/MCC.0000000000001283},
	pmid = {40522105 [Indexed for MEDLINE]}
}

@ARTICLE{10.1093/ejcts/ezaf173,
	author = {Székely M, Székely L, C Dénes M and Radovits T and Merkely B, Hartyánszky I},
	title = {Minimally invasive, transapical dual-lumened cannula for short-term left ventricular support in a clinically relevant large animal model†.},
	journal = {Eur J Cardiothorac Surg},
	year = {2025},
	abstract = {OBJECTIVES: Cardiogenic shock is still a major clinical challenge, despite the available devices. We developed a minimally invasive, transapical dual-lumened cannula, which can provide antegrade circulatory support and unloading for the left ventricle (LV). After using 3D printing technology, we wanted to test whether our prototypes are haemodynamically competent and implantable in an experimental large porcine model as a proof of concept study. METHODS: We implanted our cannula prototypes to 7 healthy porcines via median sternotomy (n = 6) and via minimally invasive access (n = 1), transapically, under fluoroscopic control, off-pump. The cannulas were connected to a heart-lung machine, and we went from 2.5, to 3.5, 4, 4.5, 5 and 5.5 l/min flow with 15-15 min intervals on each flow to ensure LV support. Different metabolic and haemodynamic parameters were continuously monitored. RESULTS: Implantation time was 14 ± 5 min. The cardiac output of the right ventricle elevated with the LV and roller pump performance from baseline of 4.81 ± 2.09 to 6.17 ± 1.02 l/min at 5.5 l/min pump flow. Mean arterial pressure and central venous pressure changed from 68.9 ± 9.4 and 9.2 ± 2.4 mmHg, to 72.8 ± 11.3 and 9.8 ± 3 mmHg, respectively. Serum lactic acid and other metabolic parameters were not changed significantly. CONCLUSIONS: We have successfully proved in a large animal study that our prototypes are implantable and can provide up to 5.5 l/min cardiac output. They could assist, then fully replace the function of the LV using a roller pump during our study. Further investigations are planned in the future using centrifugal pumps for longer-term support.},
	doi = {10.1093/ejcts/ezaf173},
	pmid = {40397992 [Indexed for MEDLINE]},
	note = {PMC12209791}
}

@ARTICLE{10.1161/JAHA.124.036367,
	author = {Bonnet G and Rommel KP and Falah B and Lansky AJ and Zhang Y and Schonning MJ and Redfors B and Burkhoff D and Cohen DJ and Basir MB and O'Neill WW and Granada JF},
	title = {Impact of Mean Blood Pressure Profiles in Percutaneous Left Ventricular Assist Device-Supported High-Risk Percutaneous Coronary Intervention: The PROTECT III Study.},
	journal = {J Am Heart Assoc},
	year = {2025},
	abstract = {BACKGROUND: Percutaneous left ventricular assist devices are used prophylactically to prevent hypotension during high-risk percutaneous coronary intervention. However, the impact of preprocedural hemodynamic profiles on procedural and clinical outcomes in these patients is unknown. METHODS AND RESULTS: Patients from the central venous access device PROTECT III registry (NCT04136392) were categorized according to preprocedural mean blood pressure (MBP). Procedural and in-hospital outcomes, including hypotensive episodes, need for prolonged percutaneous left ventricular assist device support, and in-hospital death, were compared between groups. We also assessed the relationship between preprocedural MBP and 90-day major adverse cardiovascular and cerebrovascular events, which included all-cause death, myocardial infarction, stroke/transient ischemic attack, and repeat revascularization, as well as with 1-year mortality. A total of 1159 patients underwent percutaneous left ventricular assist device-supported high-risk percutaneous coronary intervention and were stratified into 4 hemodynamic profiles of preprocedural MBP level: MBP>100 mm Hg (n=242), >90 to ≤100 mm Hg (n=264), >80 to ≤90 mm Hg (n=306), and ≤80 mm Hg (n=347). Lower preprocedural MBP was associated with baseline anemia, history of heart failure, left main disease, and transfer from another hospital. In-hospital and procedural adverse outcomes did not differ between the BP categories. However, 90-day major adverse cardiovascular and cerebrovascular events rates and 1-year mortality increased with decreasing baseline BP levels. The association between BP category and 1-year mortality remained significant after adjustment for other factors (hazard ratio [HR], 0.79 [95% CI, 0.71-0.88], P<0.001). CONCLUSIONS: In a real-world cohort undergoing high-risk percutaneous coronary intervention with percutaneous left ventricular assist device support, there was no association between hemodynamic status and in-hospital outcomes. Lower preprocedural BP was associated with higher rates of 90-day major adverse cardiovascular and cerebrovascular events and 1-year mortality. REGISTRATION: URL: https://www.clinicaltrials.gov; Unique identifier: NCT04136392.},
	doi = {10.1161/JAHA.124.036367},
	pmid = {40371603 [Indexed for MEDLINE]},
	note = {PMC12184586}
}

@ARTICLE{10.21980/J85W7R,
	author = {Roszczynialski KN and Harp AE and Fisk CA and Ng KM and Rider AC},
	title = {My Broken Heart.},
	journal = {J Educ Teach Emerg Med},
	year = {2025},
	abstract = {AUDIENCE: The target audience for the key learning objectives of this Left-Ventricular Assist Device (LVAD) simulation are emergency medicine residents. Other team members such as attendings, nurses, pharmacists, and technicians could potentially be integrated. INTRODUCTION: Left ventricular assist devices (LVADs) are common bridge therapy for patients suffering from severe heart failure to cardiac transplant or destination therapy for non-transplant candidates.1 Emergency medicine physicians must be prepared for a variety of device complications that may result in an acute care presentation, such as drive-line infections, suction events, arrhythmias, and cardiac arrest with device failure. In a review investigating ED presentations for patients with LVADs, device-specific complaints were among the fewest, with the most common presentations involving bleeding, infection, and arrythmias.2 The present case involves a suction event that is precipitated by a gastrointestinal (GI) bleed, which has an incidence of 30% for LVAD patients.3 This case was developed for a technology failure-themed resident simulation competition during the Western Society for Academic Emergency Medicine (SEAM) conference held on April 1, 2022. EDUCATIONAL OBJECTIVES: By the end of this simulation session, learners will be able to: 1) assess the hemodynamics of an LVAD patient by using a Doppler to determine mean arterial pressure, 2) Manage an arrhythmia in an LVAD patient with a suction event by addressing preload, 3) Identify and treat the source of hypovolemia (a massive lower gastrointestinal hemorrhage), 4) Perform clear closed-loop communication with other team members. EDUCATIONAL METHODS: This high-fidelity simulation case aims to train emergency medicine residents on recognition and management of an LVAD suction event, a rare but serious presentation encountered in the emergency department. This simulation can be successfully implemented either in situ, in an immersive simulation center, or off-site. This case could be represented by lower fidelity mannequins without the capabilities to provide learner tactile feedback of hemodynamics or airway, with a separate monitor device such as SimMon to display vital signs and digital media to demonstrate needed clinical images. The audio file of the low-flow alarm can be accessed and played by any device with internet access. The simulation benefits from embedded simulation participants to act as the bedside nurse and wife to provide history. This simulation included debriefing focused on a critical action checklist. RESEARCH METHODS: A working group of two simulation-trained faculty, a simulation fellow, and three senior emergency medicine residents chose and developed the simulation case. Two simulation-trained faculty implemented the pilot case series to gather feedback on performance against the critical action checklist. One simulation-trained faculty then facilitated two additional in situ sessions, again evaluating performance on the critical actions as well as content of the debrief discussion. That data was used to iteratively edit the presentation and dynamics of the case in preparation for the SIMposium case competition. RESULTS: During March 2022, in a three-case pilot in situ series, a total of 15 residents (five EM PGY4, four EM PGY3, five EM PGY2, one off-service PGY1) and two medical students (MS3) participated in the simulation case. Participant reactions were overwhelmingly positive, particularly from senior residents. The final version of the SIMposium case was held for a team of four emergency medicine residents from an alternate institution, all critical actions were met, and a discussion point arose regarding the reversal of anticoagulation in LVAD patients with acute GI bleed. DISCUSSION: Overall, this simulation was well received, effective, and easy to implement and translate to immersive, in situ, or offsite locations for the training of emergency medicine residents on the management of a high acuity, low-frequency event of LVAD device complication. Each debrief stimulated an excellent discussion regarding the general management of LVAD patients regarding initial assessment, arrhythmia, and distinguishing pathologies from device alarms. Our main takeaway from this simulation was the power of a case involving a critical and high acuity patient with LVAD which stimulated residents to engage in more robust discussions during debriefing, leading to broader clinical learning. TOPICS: In situ simulation, simulation competition, LVAD, left ventricular assist device.},
	doi = {10.21980/J85W7R},
	pmid = {40336694},
	note = {PMC12054096}
}

@ARTICLE{10.1016/j.jhlto.2024.100190,
	author = {Ahmed MM and Grant H and Martinez J and Thomas J and Al-Ani M and Parker A and Vilaro J and Aranda J and Chivukula VK},
	title = {Patient-specific hemodynamic modeling to optimize LVAD speed and right heart health.},
	journal = {JHLT Open},
	year = {2024},
	abstract = {BACKGROUND: Left ventricular assist device (LVAD) speed optimization and right heart failure post device implantation are major clinical challenges. Right heart catheterization (RHC)-guided speed titration studies are often performed to optimize LVAD settings, which are unknown and must be optimized for each patient. A virtual hemodynamic model (VHM) that can be tailored to each patient may provide useful guidance and reduce repeated studies. METHODS: We conducted a retrospective analysis on 16 patients implanted with HeartMate 3 (HM3) who underwent RHC speed titration study as an outpatient. A custom-designed VHM was built and customized for each patient based on RHC measurements. VHM predictions were obtained for multiple scenarios: (1) population-based pulmonary system parameters, (2) patient-specific systemic and pulmonary resistance and capacitance parameters, (3) clinical optimization-based patient-specific mean arterial pressure (MAP), and (4) several MAP targets ranging from 70 to 90 mm Hg. RESULTS: All patients who underwent RHC speed titration had a clinician-guided speed increase, with a median increase of 300 revolutions per minute (rpm). Using each patient's customized VHM, virtual speed optimization demonstrated congruence with clinician-guided optimization, with a median predicted speed increase of 321 rpm. After virtual optimization, there was a decrease in the pulmonary artery pressure for 13 patients (81.25%), indicating a predicted improvement in pulmonary parameters. CONCLUSIONS: For our cohort of 16 patients, there was an overall congruence between clinician-guided and patient-specific VHM-predicted optimal LVAD speeds. The magnitude of speed change varied depending on individual patient targets. This may provide individualized speed titration goals and lessen the need for repeat invasive studies.},
	doi = {10.1016/j.jhlto.2024.100190},
	pmid = {40144814},
	note = {PMC11935428}
}

@ARTICLE{10.1016/j.cardfail.2025.01.017,
	author = {Kanelidis AJ and Gozdecki L and Belkin MN and Kalantari S and Nguyen A and Chung BB and Swat S and Sarswat N and Kim G and Chickerillo K and Okray J and Hubbell A and Creighton SK and Jung CY and Bole I and Saffari SE and O'Connor M and Ota T and Jeevanandam V and Salerno C and Grinstein J},
	title = {Mitigating Post-operative Right Ventricular Dysfunction After Left Ventricular Assist Device: The RV Protection Study.},
	journal = {J Card Fail},
	year = {2026},
	abstract = {BACKGROUND: Despite improvements in hemocompatibility-related adverse events (HRAEs) with the HeartMate 3 left ventricular assist device (LVAD), hemodynamic-related events (HDREs), such as right ventricular failure (RVF) and aortic insufficiency, still result in considerable morbidity and mortality. We investigated a comprehensive, upfront RV protection strategy combining hemodynamic, ventilatory and pharmaceutical optimization to mitigate the risk of RVF. METHODS/RESULTS: Participants were prospectively randomized in a 1:1 fashion to either the RV-protection strategy or usual care for post-operative LVAD management. The RV-protection strategy targeted RV afterload (inhaled NO ≥ 48 hrs, PCWP < 18), RV preload (CVP 8-14), RV perfusion (MAP 70-90, Hgb > 8), RV contractility (IV inotropes), rate/rhythm control (HR >100, normal sinus), ventilatory management (SpO2 >95, PaCO2 < 50, plateau pressure < 30, PEEP ≤ 5), and RV geometry (echo-guided septal position). The primary outcome was survival free from any HDREs or HRAEs at 24 weeks. Secondary outcomes included severe RVF, according to INTERMACS and ARC definitions. Twenty participants were randomized: 10 to the RV-protection strategy and 10 to usual care. The median age was 60 years (IQR 54-69), 50% were Black, and 50% had ischemia. At 24 weeks, the RV-protection strategy showed significantly greater survival rates free from HDREs or HRAEs compared to usual care (80% vs 40%; P = 0.04). Event-free survival for HRAEs resulted in similar findings. No HDREs occurred with the RV protection strategy vs 3 (30%) with usual care (P = 0.067). Similarly, severe RVF according to INTERMACS or ARC did not occur in the RV protection strategy vs 3 (30%) in the usual-care cohort (P = 0.20). CONCLUSIONS: Participants receiving a novel, comprehensive, upfront RV protection strategy post-LVAD implantation had significantly greater survival rates free from HDREs or HRAEs at 24 weeks.},
	doi = {10.1016/j.cardfail.2025.01.017},
	pmid = {39954845 [Indexed for MEDLINE]}
}

@ARTICLE{10.1161/CIRCHEARTFAILURE.124.012016,
	author = {Hungerford SL and Everett KD and Gulati G and Sunagawa K and Burkhoff D and Kapur NK},
	title = {Systemic Circulation in Advanced Heart Failure and Cardiogenic Shock: State-of-the-Art Review.},
	journal = {Circ Heart Fail},
	year = {2025},
	abstract = {The integrative physiology of the left ventricle and systemic circulation is fundamental to our understanding of advanced heart failure and cardiogenic shock. In simplest terms, any increase in aortic stiffness increases the vascular afterload presented to the failing left ventricle. The net effect is increased myocardial oxygen demand and reduced coronary perfusion pressure, thereby further deteriorating contractile function. Although mechanical circulatory support devices should theoretically work in concert with guideline-directed medical therapy, cardiac resynchronization and inotropic and vasopressor agents designed to support myocardial performance and enhance left ventricle recovery, this does not always occur. Each therapy and intervention may result in vastly different and sometimes deleterious effects on vascular afterload. Although best described by a combination of both steady-state and pulsatile components, the latter is frequently overlooked when mean arterial pressure or systemic vascular resistance alone is used to quantify vascular afterload in advanced heart failure and cardiogenic shock. In this state-of-the-art review, we examine what is known about vascular afterload in advanced heart failure and cardiogenic shock, including the use of temporary and permanent mechanical circulatory support systems. Importantly, we outline 4 key components for a more complete assessment of vascular afterload. Unlike previous discussions on this topic, we set aside considerations of venous return and ventricular preload, as important as they are, to focus exclusively on the hydraulic load within the systemic circulation against which the impaired left ventricle must contract.},
	doi = {10.1161/CIRCHEARTFAILURE.124.012016},
	pmid = {39829435 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.jcin.2024.09.017,
	author = {Schwammenthal E and Gogorishvili I and Sievert H and Fefer P and Pinto DS},
	title = {High-Output Mechanical Circulatory Support in Left Main Interventions: The Magenta Elevate High-Risk PCI First-in-Human Study.},
	journal = {JACC Cardiovasc Interv},
	year = {2024},
	abstract = {BACKGROUND: The Magenta Elevate is a 9-F, self-expanding, catheter-mounted pump delivered sheathed through a commercially available 10-F femoral introducer over the wire to the left ventricle (LV), providing temporary hemodynamic support up to an equivalent of normal cardiac output. OBJECTIVES: The authors sought to assess the feasibility and outcomes of Elevate-supported high-risk percutaneous coronary intervention (HR-PCI) in a first-in-human study and study the hemodynamic impact of high-output support during prolonged interventional left main coronary artery (LM) occlusions. METHODS: In this study, 14 patients underwent Elevate-supported HR-PCI, with 8 patients undergoing 20 prolonged (39 ± 16 seconds) balloon occlusions of an unprotected LM. Systolic and diastolic aortic pressures, mean arterial pressure (MAP), and diastolic aorto-left ventricular pressure difference (dΔPAoLV) were determined before and during inflations. RESULTS: There were no major device-related adverse events (primary safety endpoint) and no mortality at 30 days. During prolonged LM occlusions, the following changes were observed: There was a significant drop in systolic aortic pressure (-35 mm Hg [-46 to -23 mm Hg]; P < 0.0001) accompanied by a significant increase in diastolic pressure (7 mm Hg [4 to 10 mm Hg]; P < 0.0055). MAP, which showed a small decrease (-7 mm Hg [-13 to -2 mm Hg]; P < 0.001) and dΔPAoLV (-2 mm Hg [-5 to 4 mm Hg]; P = 0.51) remained in the normal range. Ventriculo-arterial uncoupling occurred in 13 of 20 LM balloon occlusions. CONCLUSIONS: In this first-in-human study, use of the Magenta Elevate low-profile, high-output catheter during HR-PCI was safe and provided substantial cardiac support. During prolonged interventional LM occlusions, the system unloaded the LV, maintaining a normal MAP and dΔPAoLV.},
	doi = {10.1016/j.jcin.2024.09.017},
	pmid = {39722267 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/jcm13237418,
	author = {Hasabo EA and Isik B and Elgadi A and Eljack MMF and Yacoub MS and Elzomor H and Sultan S and Caliskan K and Soliman O},
	title = {A Systematic Review and Meta-Analysis of the Efficacy and Safety of Sodium-Glucose Cotransporter-2 Inhibitor in Patients Using Left Ventricular Assist Devices.},
	journal = {J Clin Med},
	year = {2024},
	abstract = {Background: Sodium-glucose cotransporter-2 inhibitors (SGLT2-i) have been shown to reduce risks of clinical events in patients with heart failure (HF). However, data on the use of SGLT2-i in patients with left ventricular assist devices (LVADs) are scarce. We thought to assess the efficacy and safety of SGLT2-i in patients with LVADs. Methods: A systematic search was conducted in PubMed, Scopus, Web of Science, Embase, and Cochrane from inception to November 2024. We used all relevant words for "SGLT2-i" and "LVAD" to search in databases, and we included studies and published abstracts in peer-reviewed journals of studies that assessed SGLT2-i in patients with LVAD. Results: Four studies and seven abstracts totaling 228 patients using SGLT2-i were included. Empagliflozin, Dapagliflozin, and Canagliflozin were the used SGLT2-i across the included studies. Pooled analysis showed that SGLT2-i significantly improved ejection fraction (EF) (Mean= 4.2, 95% CI [1.22, 7.19]) and hemoglobin A1c (HbA1c) (Mean = -0.44, 95% CI [-0.79, -0.09]) from baseline. However, no significant changes in B-type natriuretic peptide (BNP), or glomerular filtration rate (GFR) were noticed. Other outcomes of interest not included in the meta-analysis did not show significant changes, such as cardiac index (CI), left ventricular end-systolic diameter (LVESD), left ventricular end-diastolic diameter (LVEDD), mean arterial pressure (MAP), or mean pulmonary artery pressure (MPAP). The pooled percentage of people with driveline infection was 9%, 95% CI (3, 19). Conclusions: SGLT2-i effectively improves EF and HbA1c in patients using LVAD. Further adequately powered randomized studies are warranted to ascertain its clinical efficacy and safety in that unique population.},
	doi = {10.3390/jcm13237418},
	pmid = {39685874},
	note = {PMC11641912}
}

@ARTICLE{10.1007/s10286-024-01086-5,
	author = {Warnakulasuriya T and George B and Lever N and Ramchandra R},
	title = {Mechanical circulatory support reduces renal sympathetic nerve activity in an ovine model of acute myocardial infarction.},
	journal = {Clin Auton Res},
	year = {2025},
	abstract = {PURPOSE: The use of circulatory assist devices has been shown to improve glomerular filtration rate and reduce the incidence of acute kidney injury in patients following acute cardiac pathology. However, the mechanisms of improvement in kidney function are not clear. We tested the hypothesis that mechanical circulatory support would result in a decrease in directly recorded renal sympathetic nerve activity (RSNA) and mediate the improvement in renal blood flow (RBF) in a setting of acute myocardial infarction (AMI)-induced left ventricular systolic dysfunction. METHODS: An anaesthetized ovine model was used to induce AMI (n = 8) using injections of microspheres into the left coronary artery in one group. The second group did not undergo embolization (n = 6). The effects of mechanical circulatory support using the Impella CP on directly recorded renal sympathetic nerve activity were examined in these two groups of animals. RESULTS: Injection of microspheres resulted in a drop in mean arterial pressure (MAP) of 21 ± 4 mmHg compared to baseline values (p < 0.05; n = 8). This was associated with a 67% increase in renal sympathetic nerve activity (RSNA; from 16 ± 5 to 21 ± 5 spikes/s; p < 0.05; n = 7). Impella CP support significantly increased MAP by 13 ± 1.5 mmHg at pump level 8 (p < 0.05) in the AMI group. Incremental pump support resulted in a significant decrease in RSNA (p < 0.05) in both groups. At pump level P8 in the AMI group, RSNA was decreased by 21 ± 5.5% compared to pump level P0 when the pump was not on. CONCLUSION: Our data indicate that the improvement in kidney function following mechanical circulatory support may be mediated in part by renal sympathoinhibition.},
	doi = {10.1007/s10286-024-01086-5},
	pmid = {39601940 [Indexed for MEDLINE]},
	note = {PMC12000230}
}

@ARTICLE{10.1001/jamacardio.2024.4197,
	author = {Udesen NLJ and Beske RP and Hassager C and Jensen LO, Eiskjær H and Mangner N and Polzin A and Schulze PC and Skurk C and Nordbeck P and Clemmensen P and Panoulas V and Zimmer S, Schäfer A and Werner N and Frydland M and Holmvang L, Kjærgaard J, Engstøm T and Schmidt H and Junker A and Terkelsen CJ and Christensen S and Linke A, Møller JE; DanGer Shock Investigators},
