@ARTICLE{10.1111/aor.14891,
	author = {Romero Dorta E and Meyn R, Müller M and Hoermandinger C and Schoenrath F and Falk V and Meyer A and Merke N and Potapov E and Mulzer J and Knierim J},
	title = {Potential benefits of aortic valve opening in patients with left ventricular assist devices.},
	journal = {Artif Organs},
	year = {2025},
	abstract = {BACKGROUND: Aortic regurgitation (AR) is a well-known cause of impaired outcome in patients with centrifugal left ventricular assist devices (cfLVADs). The failure of the aortic valve (AV) to open at least intermittently is associated with cusp remodeling, commissural fusion, and ultimately developing AR. Our aim was to characterize patients in whom AV opening (AVO) was preserved 6 months after implantation and identify determinants related to it. METHODS AND RESULTS: We conducted standardized echocardiography and collected clinical and laboratory tests at the outpatient clinic 6 months after implantation. We classified patients into those showing intermittently opening of the AV, every 2-3 beats, or in every cycle (AVO) and those whose AV was continuously closed (NAVO). From the 219 cfLVAD implanted in our center between March 2018 and January 2020, 156 subjects were alive and on the device after 6 months. In 2 of the reviewed echocardiograms, we could not evaluate the AV. 99 patients (64%) showed AVO compared to 55 (36%) with NAVO. The first presented higher mean arterial pressure (84 ± 10 vs. 77 ± 13 mm Hg, p = 0.002), larger LV end-diastolic diameter (LVEDD 57.5 ± 12 vs. 52.7 ± 13 mm, p = 0.022), a better TAPSE (15 ± 4 vs. 13 ± 4 mm, p = 0.028), and less frequently significant AR than patients with NAVO (moderate/severe AR in 6% vs. in 20%, p = 0.042). In a multiple logistic regression, a lower NYHA Class, a larger LVEDD, and a better LV ejection fraction appeared as significant predictors of AVO. After a median follow-up of 3.2 years, we found no significant impact on survival stratifying patients by AVO (log-rank p = 0.53). CONCLUSION: AVO was associated with better RV function, lower NYHA Class, and a lower rate of significant AR. This could indicate that AVO should be pursued in LVAD patients.},
	doi = {10.1111/aor.14891},
	pmid = {39450776 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.cardfail.2024.07.016,
	author = {Basir MB and Bentley D and Truesdell AG and Kunkel K and Lemor A and Megaly M and Alqarqaz M and Alaswad K and Khandewal A and Jortberg E and Kalra S and Kaki A and Burkhoff D and Moses JW and Pinto DS and Stone GW and O'Neill WW},
	title = {Clinical Outcomes of Patients Experiencing Transient Loss of Pulse Pressure During High-Risk PCI with Impella.},
	journal = {J Card Fail},
	year = {2024},
	abstract = {BACKGROUND: Patients experiencing loss of pulse pressure (LOPP) during high-risk percutaneous coronary intervention (HR-PCI) are transiently dependent on mechanical circulatory support devices. We sought to define the frequency and clinic outcomes of patients who experience LOPP during HR-PCI. METHODS AND RESULTS: Patients enrolled in the PROTECT III study and had automated Impella controller logs capturing real-time hemodynamics were included in this analysis. A LOPP event was defined as a mean pulse pressure on Impella of <20 mm Hg for ≥5 seconds during PCI. Clinical characteristics and outcomes were then compared between those with and without LOPP. Logistic regression identified clinical and hemodynamic predictors of LOPP. We included 302 patients, of whom 148 patients (49%) experienced LOPP. Age, sex, and comorbidities were similar in patients with and without LOPP. Mean baseline systolic blood pressure (118.6 mm Hg vs 129.8 mm Hg; P < .001) and mean arterial pressure (86.9 mm Hg vs 91.6 mm Hg; P = .011) were lower in patients with LOPP, whereas heart rate (78 bpm vs 73 bpm; P = .012) was higher. Anatomical complexity was similar between groups. Patients with LOPP were more likely to experience major adverse cardiac and cerebrovascular events (23.5% vs 8.8%; P = .002), acute kidney injury (10.1% vs 2.6%; P = .030), and death (20.2% vs 7.9%; P = .008) within 90 days. A low baseline systolic blood pressure and cardiomyopathy were the strongest predictors of LOPP (P = .003 and P = .001, respectively). CONCLUSIONS: LOPP on Impella during HR-PCI was common and occurred more frequently in patients with cardiomyopathy and a low systolic blood pressure. LOPP was strongly associated with higher 90-day major adverse cardiac and cerebrovascular events, acute kidney injury, and mortality. Condensed Abstract We sought to define the frequency and clinic outcomes of patients who experience LOPP during high-risk percutaneous coronary intervention (HR-PCI). We included 302 patients, of whom 148 (49%) experienced LOPP. Patients with LOPP were more likely to experience major adverse cardiac and cerebrovascular events (23.5% vs 8.8%; P = .002), acute kidney injury (10.1% vs 2.6%; P = .030), and death (20.2% vs 7.9%; P = .008) within 90 days. A low baseline systolic blood pressure and cardiomyopathy were the strongest predictors of LOPP (P = .003 and P = .001, respectively).},
	doi = {10.1016/j.cardfail.2024.07.016},
	pmid = {39389740 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.cardfail.2024.07.019,
	author = {Longinow J and Martens P and Il'giovine ZJ and Higgins A and Ives L and Soltesz EG and Tong MZ and Estep JD and Starling RC and Tang WHW and Hanna M and Lee R},
	title = {Hemodynamic Response after Intra-aortic Balloon Counter-Pulsation in Cardiac Amyloidosis and Cardiogenic Shock.},
	journal = {J Card Fail},
	year = {2024},
	abstract = {BACKGROUND: In those with heart failure-related cardiogenic shock (HF-CS), an intra-aortic balloon pump (IABP) may improve hemodynamics and be useful as a bridge to advanced therapies. We explore whether those with cardiac amyloidosis and HF-CS might experience hemodynamic improvement and describe the hemodynamic response after IABP. METHODS AND RESULTS: We retrospectively identified consecutive patients with a diagnosis of cardiac amyloid, either light chain or transthyretin, who were admitted to our intensive care unit with HF-CS. Patients were excluded if an IABP was placed during heart transplant or for shock related to acute myocardial infarction. Invasive hemodynamics before and after IABP placement were assessed. We identified 23 patients with cardiac amyloid who had an IABP placed for HF-CS. The 1-year survival rate was 74% and most (65%) were bridged to heart transplant, although 1 patient was bridged to destination left ventricular assist device. After IABP, the mean arterial pressure, cardiac index, and cardiac power index were significantly increased, whereas mean right atrial pressure, mean pulmonary artery pressure, and pulmonary capillary wedge pressure were all significantly decreased. A smaller left ventricular end-diastolic diameter (per cm) was associated with a higher likelihood of a cardiac index of <2.2 L/min/m2 after IABP (odds ratio 0.16, 95% confidence interval 0.01-0.93, P = .04). CONCLUSIONS: IABP significantly improved cardiac index while decreasing right atrial pressure, mean pulmonary artery pressure, and pulmonary capillary wedge pressure in cardiac amyloidosis patients with HF-CS.},
	doi = {10.1016/j.cardfail.2024.07.019},
	pmid = {39389735 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.iccn.2024.103840,
	author = {Brandão SMG and Urasaki MBM and Yamada BFA and Lemos DM and Matos LN and Costa MTF and Nogueira PC and Santos VLCG},
	title = {Infection epidemiology, preventive measures and principles of best practices involving the skin and dressing of patients with a ventricular assist device: A scoping review.},
	journal = {Intensive Crit Care Nurs},
	year = {2025},
	abstract = {BACKGROUND: Specific knowledge of several domains for managing care in the driveline externalization area may be necessary for the broader application of left ventricular assist devices. OBJECTIVES: This study aimed to map the recommendations for adult patients undergoing left ventricular assist device implantation. DESIGN: This scoping review, is being registered in the Open Science Framework under DOI https://doi.org/10.17605/OSF.IO/Q76B3 (https://osf.io/q76b3/). METHOD: Left ventricular assist device coordinators and nurse specialists in dermatology and stomatherapy conducted a scoping review limited to the period between 2015 and 2022. The results of this scoping review will be discussed and presented separately in 3 articles. This third article synthesizes research evidence on the epidemiology of device infections, infection preventive measures, local skin care and dressings in adult patients with left ventricular assist devices. RESULTS: The initial search resulted in 771 studies. Sixty nine met the eligibility criteria and were included in the scoping review. Eighteen articles addressing the epidemiology of device infections, infection preventive measures, and local skin and dressing care that answered the question of this article were included. The most common bacterial pathogens reported have been Gram-positive bacteria, typically Staphylococcus species. With respect to infection preventive measures, there are evidence gaps in local skin care and transmission system dressings. CONCLUSION: The driveline still remains the most common type of device infection. There exists imperfect knowledge on the standardization of care with the dressing and the area of skin for left ventricular assist device patients. Furthermore, there is a methodological fragility of the studies. These elements imply an opportunity for future research on these subjects. IMPLICATIONS FOR CLINICAL PRACTICE: This review provides an overview of the principles of best practices involving the skin and dressing of patients with a ventricular assist device without local dermatological diseases or infectious diseases. The central figure of an experienced professional can make a difference.},
	doi = {10.1016/j.iccn.2024.103840},
	pmid = {39306939 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/ejhf.3471,
	author = {Kondo T and Yoshizumi T and Morimoto R and Imaizumi T and Kazama S and Hiraiwa H and Okumura T and Murohara T and Mutsuga M},
	title = {Predicting survival after Impella implantation in patients with cardiogenic shock: The J-PVAD risk score.},
	abstract = {AIMS: Impella has become a new option for mechanical circulatory support in patients with cardiogenic shock (CS); however, prognostic models for patients after Impella are lacking. We aimed to identify the factors that predict in-hospital mortality in patients with CS requiring Impella and develop a new risk prediction model. METHODS AND RESULTS: We utilized the J-PVAD registry, which includes all cases where Impella was implanted in Japan. Two-thirds of the patients in the J-PVAD registry were randomly assigned to the derivation cohort (n = 1701), and the other third was assigned to the validation cohort (n = 850). A backward stepwise logistic regression model was developed to identify factors associated with in-hospital mortality. In the derivation cohort, 956 patients were discharged alive, and 745 patients (43.8%) died during hospitalization. Among 29 candidate variables, 12 were independently associated with in-hospital mortality and were applied as components of the risk model, including age, sex, body mass index, fulminant myocarditis aetiology, cardiac arrest in hospital, baseline veno-arterial extracorporeal membrane oxygenation use, mean arterial pressure, lactate, lactate dehydrogenase, total bilirubin, creatinine, and albumin levels. The comparison of predicted and observed in-hospital mortality according to the 7th quantiles using the J-PVAD risk score showed good calibration. The area under the curve for the J-PVAD risk score was 0.76 (95% confidence interval 0.73-0.78). In the validation cohort, the J-PVAD risk score showed good calibration and discrimination ability. CONCLUSIONS: The J-PVAD risk score can be calculated using variables easily obtained in routine clinical practice. It helps the accurate stratification of mortality risk and facilitates clinical decision-making.},
	doi = {10.1002/ejhf.3471},
	pmid = {39300761 [Indexed for MEDLINE]},
	note = {PMC11798632}
}

@ARTICLE{10.1111/aor.14854,
	author = {Barua S and Robson D and Eckford H and Macdonald P and Muthiah K and Hayward CS},
	title = {Renal resistive index in patients supported with a durable continuous flow left ventricular assist device.},
	abstract = {BACKGROUND: The impact of continuous flow resulting from contemporary left ventricular assist devices (LVAD) on renal vascular physiology is unknown. Renal resistive index (RRI) reflects arterial compliance, as well as renal vascular resistance, contributed by afferent and efferent arteriolar tone, the renal interstitium as well as renal venous pressures. METHODS: Prospective, single center study with renal Doppler evaluation at baseline (pre-implant) and at 3-months support. Outcomes assessed include need for post-operative renal replacement therapy (RRT), worsening renal function (WRF) defined as persistent increase from pre-implant KDIGO chronic kidney disease stage, right ventricular (RV) failure, and survival to transplantation. RESULTS: Pre-implant RRI did not predict cardiorenal outcomes including right heart failure, need for renal replacement therapy or worsening renal function. Post-implant RRI was significantly lower than pre-implant RRI, with a distinct Doppler waveform characteristic of continuous flow. Post-implant renal end-diastolic velocity, but not RRI, correlated strongly with LVAD flow (Spearman rho -0.99, p < 0.001), with trend toward correlation with mean arterial pressure (Spearman's rho 0.63, p = 0.129). There was a negative correlation between post-implant RRI and mean pulmonary artery pressure (Spearman's rho -0.81, p = 0.049), likely driven by elevated pulmonary capillary wedge pressure (Spearman's rho -0.83, p = 0.058). CONCLUSION: The hemodynamic contributors to RRI in LVAD supported patients are complex. Higher mean pulmonary artery and pulmonary capillary wedge pressures seen in lower RRI may reflect a smaller difference in systolic and diastolic flow. Future simultaneous Doppler assessment of the LVAD outflow graft and RRI may help understand the hemodynamic interactions contributing to this index.},
	doi = {10.1111/aor.14854},
	pmid = {39235223 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.acvd.2024.04.005,
	author = {Cherbi M and Merdji H, Labbé V and Bonnefoy E and Lamblin N and Roubille F and Levy B and Lim P and Khachab H and Schurtz G and Harbaoui B and Vanzetto G and Combaret N and Marchandot B and Lattuca B and Biendel-Picquet C and Leurent G and Gerbaud E and Puymirat E and Bonello L and Delmas C},
	title = {Cardiogenic shock and infection: A lethal combination.},
	journal = {Arch Cardiovasc Dis},
	year = {2024},
	abstract = {BACKGROUND: Cardiogenic shock and sepsis are severe haemodynamic states that are frequently present concomitantly, leading to substantial mortality. Despite its frequency and clinical significance, there is a striking lack of literature on the outcomes of combined sepsis and cardiogenic shock. METHODS: FRENSHOCK was a prospective registry including 772 patients with cardiogenic shock from 49 centres. The primary endpoint was 1-month all-cause mortality. Secondary endpoints included heart transplantation, ventricular assistance device and all-cause death rate at 1year. RESULTS: Among the 772 patients with cardiogenic shock included, 92 cases were triggered by sepsis (11.9%), displaying more frequent renal and hepatic acute injuries, with lower mean arterial pressure. Patients in the sepsis group required broader use of dobutamine (90.1% vs. 81.2%; P=0.16), norepinephrine (72.5% vs. 50.8%; P<0.01), renal replacement therapy (29.7% vs. 14%; P<0.01), non-invasive ventilation (36.3% vs. 24.4%; P=0.09) and invasive ventilation (52.7% vs. 35.9%; P=0.02). Sepsis-triggered cardiogenic shock resulted in higher 1-month (41.3% vs. 24.0%; adjusted hazard ratio: 1.94, 95% confidence interval: 1.36-2.76; P<0.01) and 1-year (62.0% vs. 42.9%; adjusted hazard ratio 1.75, 95% confidence interval 1.32-2.33; P<0.01) all-cause death rates. No significant difference was found at 1year for heart transplantation or ventricular assistance device (8.7% vs. 10.3%; adjusted odds ratio 0.72, 95% confidence interval 0.32-1.64; P=0.43). In patients with sepsis-triggered cardiogenic shock, neither the presence of a preexisting cardiomyopathy nor the co-occurrence of other cardiogenic shock triggers had any additional impact on death. CONCLUSIONS: The association between sepsis and cardiogenic shock represents a common high-risk scenario, leading to higher short- and long-term death rates, regardless of the association with other cardiogenic shock triggers or the presence of preexisting cardiomyopathy.},
	doi = {10.1016/j.acvd.2024.04.005},
	pmid = {39048471 [Indexed for MEDLINE]}
}

@ARTICLE{10.1007/s13239-024-00743-0,
	author = {Monreal G and Koenig SC and Kelley JF and Illg JJ and Tamez D and Kelley MS and Yetukuri V and Cross DP and Theran ME and Slaughter MS},
	title = {Early-stage Development of the CoRISMA Mechanical Circulatory Support (CMCS) System for Heart Failure Therapy.},
	journal = {Cardiovasc Eng Technol},
	year = {2024},
	abstract = {PURPOSE: CoRISMA MCS Systems Inc (Hamden CT) is developing an innovative mechanical circulatory support system (CMCS) as a durable therapeutic option for heart failure (HF) patients. The CMCS system is comprised of an axial flow pump, non-contacting hydrodynamic bearings, and integrated DC motor designed to be fully implantable in a left atrial (LA) to aortic (Ao) configuration; this unloading strategy may be particularly beneficial for HF patients with preserved ejection fraction (HFpEF). The small (5.5 cm3), lightweight (20 g), and low power (5-7 W) device design should allow for a less invasive off-pump implant. We present early-stage engineering development and testing of the prototype CoRISMA pumps. METHODS: Computational fluid dynamics (CFD) modeling was performed to evaluate flow and shear in two impeller (3 blades, 0.5 mm thickness, 8.9 mm diameter, 0.15 mm gap, polished titanium) and diffusor (5 blades, polished titanium) candidate designs. Test apparatuses were custom built to expedite development of the impeller/diffuser designs and iteratively refine the CFD models. Two candidate impeller/diffusor designs were fabricated and tested in each of the two test apparatuses (n = 4 impeller/diffuser + test fixture configurations) in static mock flow loops (hydrodynamic H-Q curves, 3.5 cP glycerol solution at 37 °C), and in dynamic mock flow loops (hemodynamics, 3.5 cP glycerol solution at 37 °C) tuned to HF conditions (mean aortic pressure 50 mmHg, central venous pressure 15 mmHg, aortic flow 3.0 L/min, and heart rate 80 bpm). RESULTS: CFD predicted flows of 4.56 L/min and 4.82 L/min at 100 mmHg for impellers/diffusers 1 and 2, respectively. Impeller 2 required less torque to generate a 6% increase in fluidic flow, and the diffuser had a larger area of high pressure, indicative of lower friction, which likely contributed to the increased efficiency. Experimental testing for all four configurations in the static and dynamic mock loops met performance metrics as evidenced by generating 4.0-4.5 L/min flow against 70-76 mmHg pressure at 25,000 rpm and restoring hemodynamics in the dynamic mock flow loop (MAP = 80 mmHg, CVP = 0 mmHg, total flow = 5.5 L/min) from baseline simulated HF test conditions. CONCLUSION: These results demonstrate proof-of-concept of the early engineering design and performance of the prototype CoRISMA pumps. Engineering specifications, challenges observed, and proposed solutions for the next design iteration were identified for the continued development of an effective, reliable, and safe LA-to-Ao CMCS system for HF patients. Current design plans are underway for incorporating a wireless energy transfer system for communication and power, eliminating the need for and complications associated with an external driveline, to achieve a fully-implantable system.},
	doi = {10.1007/s13239-024-00743-0},
	pmid = {39037566 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.jacadv.2024.100916,
	author = {Lamba HK and Kim M and Li M and Civitello AB and Nair AP and Simpson L and Herlihy JP and Frazier OH and Rogers JG and Loor G and Liao KK and Shafii AE and Chatterjee S},
	title = {Predictors and Impact of Prolonged Vasoplegia After Continuous-Flow Left Ventricular Assist Device Implantation.},
	journal = {JACC Adv},
	year = {2024},
	abstract = {BACKGROUND: Vasoplegia after cardiac surgery is associated with adverse outcomes. However, the clinical effects of vasoplegia and the significance of its duration after continuous-flow left ventricular assist device (CF-LVAD) implantation are less known. OBJECTIVES: This study aimed to identify predictors of and outcomes from transient vs prolonged vasoplegia after CF-LVAD implantation. METHODS: The study was a retrospective review of consecutive patients who underwent CF-LVAD implantation between January 1, 2005, and December 31, 2017. Vasoplegia was defined as the presence of all of the following: mean arterial pressure ≤65 mm Hg, vasopressor (epinephrine, norepinephrine, vasopressin, or dopamine) use for >6 hours within the first 24 hours postoperatively, cardiac index ≥2.2 L/min/m2 and systemic vascular resistance <800 dyne/s/cm5, and vasodilatory shock not attributable to other causes. Prolonged vasoplegia was defined as that lasting 12 to 24 hours; transient vasoplegia was that lasting 6 to <12 hours. Patient characteristics, outcomes, and risk factors were analyzed. RESULTS: Of the 600 patients who underwent CF-LVAD implantation during the study period, 182 (30.3%) developed vasoplegia. Mean patient age was similar between the vasoplegia and no-vasoplegia groups. Prolonged vasoplegia (n = 78; 13.0%), compared with transient vasoplegia (n = 104; 17.3%), was associated with greater 30-day mortality (16.7% vs 5.8%; P = 0.02). Risk factors for prolonged vasoplegia included preoperative dialysis and elevated body mass index. CONCLUSIONS: Compared with vasoplegia overall, prolonged vasoplegia was associated with worse survival after CF-LVAD implantation. Treatment to avoid or minimize progression to prolonged vasoplegia may be warranted.},
	doi = {10.1016/j.jacadv.2024.100916},
	pmid = {38939630},
	note = {PMC11198707}
}

@ARTICLE{10.1016/j.iccn.2024.103726,
	author = {Michelly Gonçalves Brandão S and Belletti Mutt Urasaki M and Machado Pires Lemos D and Neres Matos L and Takahashi M and Cristina Nogueira P and Lucia Conceição de Gouveia Santos V},
	title = {Risk factors, diagnostic methods and treatment of infection in adult patients undergoing left ventricular assist device implantation: A scoping review.},
	journal = {Intensive Crit Care Nurs},
	year = {2024},
	abstract = {BACKGROUND: Evidence on infection risk factors is scarce, and precise localization of the site of infection and its treatment remain clinically challenging. OBJECTIVES: This study aimed to map the recommendations for adult patients undergoing left ventricular assist device implantation. DESIGN: This is a scoping review, registered in the Open Science Framework under DOI10.17605/OSF.IO/Q76B3(https://osf.io/q76b3/). METHOD: This is a scoping review limited to the period between 2015 and 2022.The results of this scoping review are discussed and presented separately in 3 articles. This second paper synthesizes research evidence on the risk factors, diagnostic methods and treatment of infection in adult patients undergoing left ventricular assist device implantation. RESULTS: The initial searches identified 771 studies. Sixty-nine patients met the eligibility criteria and were included in the scoping review. Forty-three articles addressing the risk factors, diagnosis and treatment of infection were included to answer the questions of this review. CONCLUSION: Obesity has been shown to be the most common risk factor for the described process of infection by left ventricular assist devices.18F-fluorodeoxyglucose positron emission tomography showed high sensitivity in detecting cardiac device infection, and labeled leukocyte or gallium citrate-67 scintigraphy showed high specificity for left ventricular assist device infections; therefore, it can help differentiate infection from inflammation, particularly in patients with equivocal fluorodeoxyglucose positron emission tomography. Also, this review brings and discusses the limitations and strengths of diagnostic tests, the knowledge regarding the risk factors for left ventricular assist device infection, the therapeutic heterogeneity, the methodological issues of the studies, and the vast opportunity for future research on left ventricular assist device. IMPLICATIONS FOR CLINICAL PRACTICE: Ventricular assist device professionals should evaluate risk factors prior to device implantation and periodically.18F-fluorodeoxyglucose positron emission tomography should be considered as diagnostic tool in detecting superficial and deep driveline infections. Early treatment, including chronic suppressive therapy and serial surgical debridement, combined with driveline exteriorization and delayed driveline relocation may constitute a potential therapeutic strategy for deep driveline infections.},
	doi = {10.1016/j.iccn.2024.103726},
	pmid = {38852239 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/ehf2.14780,
	author = {Frederiksen PH and Linde L and Gregers E and Udesen NLJ and Helgestad OK and Banke A and Dahl JS and Jensen LO and Lassen JF and Povlsen AL and Larsen JP and Schmidt H and Ravn HB, Møller JE},
	title = {Haemodynamic implications of VA-ECMO vs. VA-ECMO plus Impella CP for cardiogenic shock in a large animal model.},
	abstract = {AIMS: Veno-arterial extracorporeal membrane oxygenation (VA-ECMO) with profound left ventricular (LV) failure is associated with inadequate LV emptying. To unload the LV, VA-ECMO can be combined with Impella CP (ECMELLA). We hypothesized that ECMELLA improves cardiac energetics compared with VA-ECMO in a porcine model of cardiogenic shock (CS). METHODS AND RESULTS: Land-race pigs (weight 70 kg) were instrumented, including a LV conductance catheter and a carotid artery Doppler flow probe. CS was induced with embolization in the left main coronary artery. CS was defined as reduction of ≥50% in cardiac output or mixed oxygen saturation (SvO2) or a SvO2 < 30%. At CS VA-ECMO was initiated and embolization was continued until arterial pulse pressure was <10 mmHg. At this point, Impella CP was placed in the ECMELLA arm. Support was maintained for 4 h. CS was induced in 15 pigs (VA-ECMO n = 7, ECMELLA n = 8). At time of CS MAP was <45 mmHg in both groups, with no difference at 4 h (VA-ECMO 64 mmHg ± 11 vs. ECMELLA 55 mmHg ± 21, P = 0.08). Carotid blood flow and arterial lactate increased from CS and was similar in VA-ECMO and ECMELLA [239 mL/min ± 97 vs. 213 mL/min ± 133 (P = 0.6) and 5.2 ± 3.3 vs. 4.2 ± 2.9 mmol/ (P = 0.5)]. Pressure-volume area (PVA) was significantly higher with VA-ECMO compared with ECMELLA (9567 ± 1733 vs. 6921 ± 5036 mmHg × mL/min × 10-3, P = 0.014). Total diureses was found to be lower in VA-ECMO compared with ECMELLA [248 mL (179-930) vs. 506 mL (418-2190); P = 0.005]. CONCLUSIONS: In a porcine model of CS, we found lower PVA, with the ECMELLA configuration compared with VA-ECMO, indicating better cardiac energetics without compromising systemic perfusion.},
	doi = {10.1002/ehf2.14780},
	pmid = {38649295 [Indexed for MEDLINE]},
	note = {PMC11287291}
}

@ARTICLE{10.1002/ccd.31043,
	author = {Ashraf H and Patel M and Armas IS and Jumean M},
	title = {Ventriculo-arterial uncoupling with an impella assisted HVAD: The p-D LVAD.},
	journal = {Catheter Cardiovasc Interv},
	year = {2024},
	abstract = {This paper presents the novel use of a temporary percutaneous ventricular assist device (pVAD) in a 51-year-old man with an implanted durable left ventricular assist device (d-LVAD). The pre-existing left ventricular assist device was unable to successfully unload the left ventricle, and the addition of the temporary pVAD achieved successful unloading as well as a decrease in pulmonary artery pressures without compromising the function of the right ventricle allowing safe UNOS listing for orthotopic heart transplantation.},
	doi = {10.1002/ccd.31043},
	pmid = {38648353 [Indexed for MEDLINE]}
}

@ARTICLE{10.1017/S1049023X2400013X,
	author = {Larson EL and Woo J and Moon G and Liu K and Vergel M and Jenkins R and Jiang K and Darby Z and Margolis A and Kilic A},
	title = {Emergency Medical Services Protocols for Assessment and Treatment of Patients with Ventricular Assist Devices.},
	journal = {Prehosp Disaster Med},
	year = {2024},
	abstract = {BACKGROUND: Patients with ventricular assist devices (VADs) represent a growing population presenting to Emergency Medical Services (EMS), but little is known about their prehospital care. This study aimed to characterize current EMS protocols in the United States for patients with VADs. METHODS: States with state-wide EMS protocols were included. Protocols were obtained from the state EMS website. If not available, the office of the state medical director was contacted. For each state, protocols were analyzed for patient and VAD assessment and treatment variables. RESULTS: Of 32 states with state-wide EMS protocols, 21 had VAD-specific protocols. With 17 (81%) states noting a pulse may not be palpable, protocols recommended assessing alternate measures of perfusion and mean arterial pressure (MAP; 15 [71%]). Assessment of VAD was advised through listening for pump hum (20 [95%]) and alarms (20 [95%]) and checking the power supply (15 [71%]). For treatment, EMS prehospital consultation was required to begin chest compression in three (14%) states, and mechanical (device) chest compressions were not permitted in two (10%) states. Contact information for VAD coordinator was listed in a minority of five (24%) states. Transport of VAD equipment/backup bag was advised in 18 (86%) states. DISCUSSION: This national analysis of EMS protocols found VAD-specific EMS protocols are not universally adopted in the United States and are variable when implemented, highlighting a need for VAD teams to partner with EMS agencies to inform standardized protocols that optimize these patients' care.},
	doi = {10.1017/S1049023X2400013X},
	pmid = {38445327 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.iccn.2024.103658,
	author = {Brandão SMG and Urasaki MBM and Lemos DMP and Matos LN and Takahashi M and Nogueira PC, de Gouveia Santos VLC},
	title = {Perioperative interventions for the prevention of surgical wound infection in adult patients undergoing left ventricular assist devices implantation: A scoping review.},
	journal = {Intensive Crit Care Nurs},
	year = {2024},
	abstract = {BACKGROUND: Surgical wound infection is the most frequent type of care health associated infection. Lack of knowledge about the prevention of surgical wound infection in patients undergoing left ventricular assist device implantation could significantly undermine the potential benefits of surgical intervention. OBJECTIVES: This study aimed to map the recommendations for adult patients undergoing left ventricular assist device implantation. DESIGN: This is a scoping review, being registered in the Open Science Framework under DOI https://doi.org/10.17605/OSF.IO/Q76B3 (https://osf.io/q76b3/). METHOD: Left ventricular assist device coordinators and nurse specialists in dermatology and stomatherapy conducted a scoping review in Scopus, The Cochrane Database of Systematic Reviews, Cumulative Index to Nursing and Allied Health Literature (CINAHL), limited to the period between 2015 and 2022. The results of this scoping review will be discussed and presented in separate articles. This paper will synthesize research evidence on the perioperative topic. RESULTS: The initial searches resulted in 771 studies. Sixty nine met the eligibility criteria and were included in the scoping review. Eight articles addressing the perioperative topic that answered the question of this article were included. CONCLUSION: Although this scoping review included heterogeneous, and scarce studies with left ventricular assist device patients. As such, there are many promising future research directions for this topic. IMPLICATIONS FOR CLINICAL PRACTICE: Infection surveillance should be an integral part of left ventricular assist device implantation programs in health care institutions. Velvet completely buried in subcutaneous tissues reduces transmission system infection. Triple tunnel method reduces transmission system infection risk.},
	doi = {10.1016/j.iccn.2024.103658},
	pmid = {38431985 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.hlc.2023.12.007,
	author = {Slack RJ and McGain F and Cox N and French C and Cheng V and Stub D and Zakhem B and Dade F and Bloom JE and Chan W and Yang Y},
	title = {Structured Weaning From the Impella Left Ventricular Micro-Axial Pump in Acute Myocardial Infarction With Cardiogenic Shock and Protected Percutaneous Coronary Intervention: Experience From a Non-Cardiac Surgical Centre.},
	journal = {Heart Lung Circ},
	year = {2024},
	abstract = {BACKGROUND: The Impella (Abiomed, Danvers, MA, USA) temporary percutaneous left ventricular assist device is increasingly used as mechanical circulatory support in patients with acute myocardial infarction-cardiogenic shock (AMICS) or those undergoing high-risk protected percutaneous coronary intervention (PCI). The optimal weaning regimen remains to be defined. METHOD: We implemented a structured weaning protocol in a series of 10 consecutive patients receiving Impella support for protected PCI or AMICS treated with PCI in a high volume non-cardiac surgery centre. Weaning after revascularisation was titrated to native heart recovery using both haemodynamic and echocardiographic parameters. RESULTS: Ten patients (eight male, two female; aged 43-70 years) received Impella support for AMICS (80%) or protected PCI (20%). Cardiogenic shock was of Society for Cardiac Angiography & Interventions grade C-E of severity in 80%, and median left ventricular end-diastolic pressure was 31 mmHg. Protocol implementation allowed successful weaning in eight of 10 patients with a median support time of 29 hours (range, 4-48 hours). Explantation was associated with an increase in heart rate (81 vs 88 bpm; p=0.005), but no significant change in Cardiac Index (2.9 vs 2.9 L/min/m2), mean arterial pressure (79 vs 82 mmHg), vasopressor requirement (10% vs 10%), or serum lactate (1.0 vs 1.0). Median durations of intensive care and hospital stay were 3 and 6 days, respectively. At 30 days, the mortality rate was 20%, with median left ventricular ejection fraction of 40%. CONCLUSIONS: A structured and dynamic weaning protocol for patients with AMICS and protected PCI supported by the Impella device is feasible in a non-cardiac surgery centre. Larger studies are needed to assess generalisability of such a weaning protocol.},
	doi = {10.1016/j.hlc.2023.12.007},
	pmid = {38388259 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.hlc.2023.12.014,
	author = {Rajagopalan G and Balakrishnan KR and Suresh Rao KG and Ravi Kumar R and Kumar RK},
	title = {Low Mean Perfusion Pressure Indexed to Body Surface Area is a Powerful Predictor of Poor Outcomes After Heart Transplantation in Patients With High Pre-Transplant Venous Pressure: A Clinical Study With Physiological Insights From Mathematical Modelling of Biventricular Heart Failure.},
	journal = {Heart Lung Circ},
	year = {2024},
	abstract = {BACKGROUND & AIM: The deleterious consequences of chronically elevated venous pressure in patients with profound right ventricular or biventricular dysfunction are well known, including renal and hepatic dysfunction, and volume overload. The only option for these patients, if they fail optimal medical treatment, is a heart transplant, as they are not candidates for left ventricular assist device therapy. Mean perfusion pressure (MPP) is important in the outcomes of critically ill patients with high venous pressure. The question arises whether MPP is important for the outcomes of heart transplants in patients with elevated pre-transplant venous pressure. Medical management of heart failure patients with reduced ejection fraction involves lowering the systemic afterload with vasodilators while awaiting a transplant. We hypothesised that when venous pressure is elevated prior to transplant, a substantial reduction in systemic arterial elastance (Ea) through vasodilation may significantly decrease MPP, resulting in compromised end-organ function and consequent unfavourable outcomes after heart transplantation. This study aims to investigate whether a low MPP serves as a risk factor for adverse outcomes in heart transplant recipients with high venous pressure. METHOD: A retrospective analysis was conducted on 250 heart transplant recipients undergoing isolated heart transplantation at a single institution from October 2012 to March 2020. Right atrial pressure (RAP) of more than 15 mmHg was considered high. Additionally, Ea calculated as the ratio of end-systolic pressure to stroke volume, and MPP calculated as the difference between mean arterial pressure and RAP were considered in our analysis. The outcomes of transplantation were measured in terms of 90-day mortality and survival up to 7 years. RESULTS: High RAP was a significant risk factor for short-term and medium-term survival if Ea was low (<2.7 mmHg/mL, the median value). This group had 39.39% in-hospital mortality compared to 14.49% for RAP<15 mmHg (p∼0.005). When Ea was high, this difference in survival was not evident: 8% for RAP<15 mmHg vs 4.8% for RAP>15 mmHg (p∼0.550). This effect was mediated through a lower MPP, and the mortality due to lower MPP increased strikingly with higher body surface area (BSA). A negative correlation was observed between MPP indexed to BSA (MPPI) and the Model for End-Stage Liver Disease score (r∼-0.3580, p<0.0001) as well as creatinine (r∼-0.3551, p<0.0001). MPPI less than 40 mmHg/m2 was associated with poorer short-term (23.2% for MPPI<40 mmHg/m2 vs 7.1% for MPPI>40 mmHg/m2, p∼0.001) and medium-term survival. The impact of high RAP and low Ea on survival was evident even on medium-term follow-up; only 30% survival at 7 years follow-up for high RAP and low Ea vs 75% for RAP<15 mmHg (p∼0.0033). CONCLUSION: The acceptable blood pressure during vasodilator therapy in patients with high RAP needs to be higher, especially in those with higher BSA. MPPI less than 40 mmHg/m2 is a risk factor for survival, in the short and medium-term, after heart transplantation.},
	doi = {10.1016/j.hlc.2023.12.014},
	pmid = {38360502 [Indexed for MEDLINE]}
}

@ARTICLE{10.1186/s12947-023-00321-9,
	author = {Galbas MC and Straky HC and Meissner F and Reuter J and Schimmel M and Grundmann S and Czerny M and Bothe W},
	title = {Cardiac dimensions and hemodynamics in healthy juvenile Landrace swine.},
	journal = {Cardiovasc Ultrasound},
	year = {2024},
	abstract = {BACKGROUND: Swine are frequently used as animal model for cardiovascular research, especially in terms of representativity of human anatomy and physiology. Reference values for the most common species used in research are important for planning and execution of animal testing. Transesophageal echocardiography is the gold standard for intraoperative imaging, but can be technically challenging in swine. Its predecessor, epicardial echocardiography (EE), is a simple and fast intraoperative imaging technique, which allows comprehensive and goal-directed assessment. However, there are few echocardiographic studies describing echocardiographic parameters in juvenile swine, none of them using EE. Therefore, in this study, we provide a comprehensive dataset on multiple geometric and functional echocardiographic parameters, as well as basic hemodynamic parameters in swine using EE. METHODS: The data collection was performed during animal testing in ten female swine (German Landrace, 104.4 ± 13.0 kg) before left ventricular assist device implantation. Hemodynamic data was recorded continuously, before and during EE. The herein described echocardiographic measurements were acquired according to a standardized protocol, encompassing apical, left ventricular short axis and long axis as well as epiaortic windows. In total, 50 echocardiographic parameters and 10 hemodynamic parameters were assessed. RESULTS: Epicardial echocardiography was successfully performed in all animals, with a median screening time of 14 min (interquartile range 11-18 min). Referring to left ventricular function, ejection fraction was 51.6 ± 5.9% and 51.2 ± 6.2% using the Teichholz and Simpson methods, respectively. Calculated ventricular mass was 301.1 ± 64.0 g, as the left ventricular end-systolic and end-diastolic diameters were 35.3 ± 2.5 mm and 48.2 ± 3.5 mm, respectively. The mean heart rate was 103 ± 28 bpm, mean arterial pressure was 101 ± 20 mmHg and mean flow at the common carotid artery was 627 ± 203 mL/min. CONCLUSION: Epicardial echocardiography allows comprehensive assessment of most common echocardiographic parameters. Compared to humans, there are important differences in swine with respect to ventricular mass, size and wall thickness, especially in the right heart. Most hemodynamic parameters were comparable between swine and humans. This data supports study planning, animal and device selection, reinforcing the three R principles in animal research.},
	doi = {10.1186/s12947-023-00321-9},
	pmid = {38229189 [Indexed for MEDLINE]},
	note = {PMC10790455}
}

@ARTICLE{10.1097/MAT.0000000000002093,
	author = {Martinez J and Smegner K and Tomoda M and Motomura T and Chivukula VK},
	title = {Encouraging Regular Aortic Valve Opening for EVAHEART 2 LVAD Support Using Virtual Patient Hemodynamic Speed Modulation Analysis.},
	journal = {ASAIO J},
	year = {2024},
	abstract = {This study focuses on investigating the EVAHEART 2 left ventricular assist device (LVAD) toward designing optimal pump speed modulation (PSM) algorithms for encouraging aortic valve (AV) flow. A custom-designed virtual patient hemodynamic model incorporating the EVAHEART 2 pressure-flow curves, cardiac chambers, and the systemic and pulmonary circulations was developed and used in this study. Several PSM waveforms were tested to evaluate their influence on the mean arterial pressure (MAP), cardiac output (CO), and AV flow for representative heart failure patients. Baseline speeds were varied from 1,600 to 2,000 rpm. For each baseline speed, the following parameters were analyzed: 1) PSM ratio (reduced speed/baseline speed), 2) PSM duration (3-7 seconds), 3) native ventricle contractility, and 4) patient MAP of 70 and 80 mm Hg. More than 2,000 rpm virtual patient scenarios were explored. A lower baseline speed (1,600 and 1,700 rpm) produced more opportunities for AV opening and more AV flow. Higher baseline speeds (1,800 and 2,000 rpm) had lower or nonexistent AV flow. When analyzing PSM ratios, a larger reduction in speed (25%) over a longer PSM (5+ seconds) duration produced the most AV flow. Lower patient MAP and increased native ventricle contractility also contributed to improving AV opening frequency and flow. This study of the EVAHEART 2 LVAD is the first to focus on leveraging PSM to enhance pulsatility and encourage AV flow. Increased AV opening frequency can benefit aortic root hemodynamics, thereby improving patient outcomes.},
	doi = {10.1097/MAT.0000000000002093},
	pmid = {38029749 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/ehf2.14576,
	author = {Tie H and Li Z and Welp H and Guha A and Caraballo C and Deschka H and Shi R and Zheng X and Martens S and Sindermann J and Chen D and Wu Q and Martens S},
	title = {Calcium channel blockers and clinical outcomes in patients with continuous-flow left ventricular assist devices.},
	abstract = {AIMS: Current guidelines suggest calcium channel blockers (CCBs) as the second or third option for blood pressure management in patients with left ventricular assist device (LVAD). However, the clinical outcomes of patients with LVAD who receive CCBs remain unclear. Our study aims to analyse the association of CCBs with clinical outcomes in patients after LVAD implantation. METHODS AND RESULTS: This is a retrospective analysis based on the Interagency Registry for Mechanically Assisted Circulatory Support (INTERMACS) from 2006 to 2017, and adult patients who were alive with LVAD and CCB treatment information at 6 months after implantation were included. Among 10 717 patients, 1369 received CCBs 6 months after implantation, and there was an increasing trend of CCB use after LVAD. Patients receiving CCB therapy at 6 months had a similar 5 year survival rate to those not receiving CCB [49.6%, 95% confidence interval (CI): 47.5-51.7% vs. 51.1%, 95% CI: 45.3-56.7%]. In both Cox and competing risk regressions after adjusting for confounding factors, CCB treatment at 6 months after implantation was not associated with long-term mortality [hazard ratio (HR): 1.03, 95% CI: 0.91-1.17, P = 0.624 and subdistribution HR (SHR): 1.07, 95% CI: 0.95-1.22, P = 0.260]. Consistently, in time-varying models, CCB treatment was not linked to long-term mortality (HR: 0.97, 95% CI: 0.87-1.09, P = 0.682 and SHR: 1.05, 95% CI: 0.94-1.18, P = 0.359). This null association remained in subgroup analysis according to device strategy and propensity-matching analyses. Neurological dysfunction, stroke, bleeding, rehospitalization, and renal dysfunction were more likely to occur among those with CCB when compared with those without CCB treatment. CONCLUSIONS: In patients with LVAD, CCB therapy fails to show benefits in long-term survival and is associated with increased incidences of neurological dysfunction, bleeding, renal dysfunction, and rehospitalization.},
	doi = {10.1002/ehf2.14576},
	pmid = {37967837 [Indexed for MEDLINE]},
	note = {PMC10804166}
}

@ARTICLE{10.1016/j.jjcc.2023.10.008,
	author = {Saito S and Okubo S and Matsuoka T and Hirota S and Yokoyama S and Kanazawa Y and Takei Y and Tezuka M and Tsuchiya G and Konishi T and Shibasaki I and Ogata K and Fukuda H},
	title = {Impella - Current issues and future expectations for the percutaneous, microaxial flow left ventricular assist device.},
	journal = {J Cardiol},
	year = {2024},
	abstract = {The importance of temporary mechanical circulatory support for treating acute heart failure with cardiogenic shock is increasingly recognized, and Impella (Abiomed, Danvers, MA, USA) has received particular attention in this regard. Impella is an axial flow left ventricular assist device (LVAD) built into the tip of a catheter. It is inserted via a peripheral artery and implanted into the left ventricle. Although the morphology of Impella is different from a typical LVAD, it has similar actions and effects as an LVAD in terms of left ventricular drainage and aortic blood delivery. Impella increases mean arterial pressure (MAP) and systemic blood flow, thereby improving peripheral organ perfusion and promoting recovery from multiple organ failure. In addition, left ventricular unloading with increased MAP increases coronary perfusion and decreases myocardial oxygen demand, thereby promoting myocardial recovery. Impella is also useful as a mechanical vent of the left ventricle in patients supported with veno-arterial extracorporeal membrane oxygenation. Indications for Impella include emergency use for cardiogenic shock and non-emergent use during high-risk percutaneous coronary intervention and ventricular tachycardia ablation. Its intended uses for cardiogenic shock include bridge to recovery, durable device, heart transplantation, and heart surgery. Prophylactic use of Impella in high-risk patients undergoing open heart surgery to prevent postcardiotomy cardiogenic shock is also gaining attention. While there have been many case reports and retrospective studies on the benefits of Impella, there is little evidence based on sufficiently large randomized controlled trials (RCTs). Currently, several RCTs are now ongoing, which are critical to determine when, for whom, and how these devices should be used. In this review, we summarize the principles, physiology, indications, and complications of the Impella support and discuss current issues and future expectations for the device.},
	doi = {10.1016/j.jjcc.2023.10.008},
	pmid = {37926367 [Indexed for MEDLINE]}
}

@ARTICLE{10.1115/1.4063746,
	author = {D'Souza GA and Rinaldi JE and Meki M and Crusan A and Richardson E and Shinnar M and Herbertson LH},
	title = {Using a Mock Circulatory Loop as a Regulatory Science Tool to Simulate Different Heart Failure Conditions.},
	journal = {J Biomech Eng},
	year = {2024},
	abstract = {Mechanical circulatory support (MCS) device therapy is one of the primary treatment options for end-stage heart failure (HF), whereby a mechanical pump is integrated with the failing heart to maintain adequate tissue perfusion. The ISO 14708-5:2020 standard prescribes generic guidelines for nonclinical device evaluation and system performance testing of MCS devices using a mock circulatory loop (MCL). However, the utility of MCLs in premarket regulatory submissions of MCS devices is ambiguous, and the specific disease states that the device is intended to treat are not usually simulated. Hence, we aim to outline the potential of MCLs as a valuable regulatory science tool for characterizing MCS device systems by adequately representing target clinical-use HF conditions on the bench. Target pathophysiologic hemodynamics of HF conditions (i.e., cardiogenic shock (CS), left ventricular (LV) hypertrophy secondary to hypertension, and coronary artery disease), along with a healthy adult at rest and a healthy adult during exercise are provided as recommended test conditions. The conditions are characterized based on LV, aorta, and left atrium pressures using recommended cardiac hemodynamic indices such as systolic, diastolic, and mean arterial pressure, mean cardiac output (CO), cardiac cycle time, and systemic vascular resistance. This study is a first step toward standardizing MCLs to generate well-defined target HF conditions used to evaluate MCS devices.},
	doi = {10.1115/1.4063746},
	pmid = {37831143 [Indexed for MEDLINE]}
}

@ARTICLE{10.1111/aor.14655,
	author = {Georges G and Trudeau F and Potvin J and Burkhoff D, Généreux P},
	title = {Organ blood flow assessment with the ModulHeart cardiorenal support device.},
	journal = {Artif Organs},
	year = {2024},
	abstract = {BACKGROUND: ModulHeart (Puzzle Medical Devices Inc) is a novel percutaneous flow entrainment pump anchored in the descending aorta. The current study evaluates the hemodynamic effect of ModulHeart support and its impact on cerebral, myocardial, and renal blood flow. METHODS: ModulHeart was implanted in the descending aorta of four healthy calves. A ramp protocol (2000 RPM increments) was performed with the pump operating at five different speeds from 14 000 to 22 000 RPM. For each speed, pressures proximal and distal to the pump, and right heart catheterization measurements were recorded. Stable-isotope labeled microspheres were injected in the left ventricle to evaluate organ perfusion. RESULTS: Thermodilution cardiac output increased by 23% at 22 000 RPM. Greater pump speeds resulted in greater pump gradients, up to 10 mm Hg in mean arterial pressure at 22 000 RPM, without significant reduction of proximal perfusion pressures. Arterial pulse pressure remained stable at all speeds. ModulHeart was not associated with a reduction in cerebral or myocardial blood flow at any speed. Renal cortical and medullary blood flow increased by up to 50% and 40%, respectively. CONCLUSION: The ModulHeart device implanted in the descending aorta of healthy calves resulted in significant arterial pressure gradients and preserved pulse pressure. Greater pump speeds translated into greater increases in renal blood flow, with no decrease in cerebral or myocardial perfusion.},
	doi = {10.1111/aor.14655},
	pmid = {37787101 [Indexed for MEDLINE]}
}

@ARTICLE{10.1097/MAT.0000000000001984,
	author = {Bracy CL and Kobres PY and Hockstein MJ and Rao SD and Gupta R and Lam PH and Sheikh FH and Hockstein MA},
	title = {Stable Ventricular Fibrillation: A Paradigm Rather Than Septal Shift?},
	journal = {ASAIO J},
	year = {2023},
	abstract = {Awake patients in ventricular fibrillation is a phenomenon limited to patients who are mechanically supported. We describe a cohort of patients supported by left ventricular assist devices (LVADs) presenting to the emergency department (ED) at a high-volume LVAD center while in awake ventricular fibrillation (VF)/ventricular tachycardia (VT). Among 175 patients reviewed, a total of 19 LVAD patients presented to the ED in awake VF/VT between December 2015 and July},
	doi = {10.1097/MAT.0000000000001984}
}

@ARTICLE{10.1109/TBME.2023.3306888,
	author = {Bierewirtz T and Narayanaswamy K and Giuffrida R and Rese T and Bortis D and Zimpfer D and Kolar JW and Kertzscher U and Granegger M},
	title = {A Novel Pumping Principle for a Total Artificial Heart.},
	journal = {IEEE Trans Biomed Eng},
	year = {2024},
	abstract = {OBJECTIVE: Total artificial hearts (TAH) serve as a temporary treatment for severe biventricular heart failure. The limited durability and complication rates of current devices hamper long-term cardiac replacement. The aim of this study was to assess the feasibility of a novel valveless pumping principle for a durable pulsatile TAH (ShuttlePump). METHODS: The pump features a rotating and linearly shuttling piston within a cylindrical housing with two in- and outlets. With a single moving piston, the ShuttlePump delivers pulsatile flow to both systemic and pulmonary circulation. The pump and actuation system were designed iteratively based on analytical and in silico methods, utilizing finite element methods (FEM) and computational fluid dynamics (CFD). Pump characteristics were evaluated experimentally in a mock circulation loop mimicking the cardiovascular system, while hemocompatibility-related parameters were calculated numerically. RESULTS: Pump characteristics cover the entire required operating range for a TAH, providing 2.5-9 L/min of flow rate against 50-160 mmHg arterial pressures at stroke frequencies of 1.5-5 Hz while balancing left and right atrial pressures. FEM analysis showed mean overall copper losses of 8.84 W, resulting in a local maximum blood temperature rise of <2 K. The CFD results of the normalized index of hemolysis were 3.57 mg/100 L, and 95% of the pump's blood volume was exchanged after 1.42 s. CONCLUSION AND SIGNIFICANCE: This study indicates the feasibility of a novel pumping system for a TAH with numerical and experimental results substantiating further development of the ShuttlePump.},
	doi = {10.1109/TBME.2023.3306888},
	pmid = {37603484 [Indexed for MEDLINE]}
}

@ARTICLE{10.2459/JCM.0000000000001531,
	author = {Moady G and Ben Avraham B and Aviv S and Itzhaki Ben Zadok O and Atar S and Abu Akel M and Ben Gal T},
	title = {The safety of sodium-glucose co-transporter 2 inhibitors in patients with left ventricular assist device - a single center experience.},
	journal = {J Cardiovasc Med (Hagerstown)},
	year = {2023},
	abstract = {AIMS: Sodium-glucose co-transporter 2 (SGLT2) inhibitors are used increasingly for patients with heart failure or chronic kidney disease to improve cardiac and renal outcomes. The use of these medications in patients with left ventricular assist devices (LVAD) is still limited and lacks evidence regarding the safety profile. In this study, we aimed to report our experience in treating 20 patients, supported by LVAD, with SGLT2 inhibitors. METHODS: We studied the safety profile of SGLT2 inhibitors (dapagliflozin and empagliflozin) in 20 patients (mean age 64.7 ± 12.2 years, 75% male) supported by LVAD as destination therapy. All patients have diabetes mellitus and were prescribed SGLT2 inhibitors for glycemic control. RESULTS: SGLT2 inhibitors were well tolerated with no major adverse events. Few suction events were reported in three patients without the need for pump speed adjustment. There was no change in mean arterial pressure (71.1 ± 5.6 vs. 70.1 ± 4.8 mmHg, P = 0.063). Modest decline in renal function was observed in six patients within the first weeks after drug initiation. There were no events of diabetic ketoacidosis or limb amputation. CONCLUSION: SGLT2 inhibitors are safe in patients with LVAD and may potentially improve cardiovascular and renal outcomes in this special population.},
	doi = {10.2459/JCM.0000000000001531},
	pmid = {37577871 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.ijcard.2023.131259,
	author = {Chavali S and Barua S and Adji A and Robson D and Raven LM and Greenfield JR and Eckford H and Macdonald PS and Hayward CS and Muthiah K},
	title = {Safety and tolerability of sodium-glucose cotransporter-2 inhibitors in bridge-to-transplant patients supported with centrifugal-flow left ventricular assist devices.},
	journal = {Int J Cardiol},
	year = {2023},
	abstract = {BACKGROUND: The safety and tolerability of sodium-glucose cotransporter-2 inhibitors (SGLT2i) in patients with end-stage heart failure supported with left-ventricular-assist-devices (LVADs), irrespective of diabetes mellitus, is not known. METHODS: A retrospective analysis of 31 outpatients implanted with LVADs as bridge-to-transplant (BTT) was conducted. Patients with biventricular support, aged under 18 years, who were discharged from the index hospitalisation, or were prescribed SGLT2i prior to their first outpatient clinic were excluded. Patient demographics, laboratory studies, pump haemodynamic and adverse event data was collected. RESULTS: Sixteen (51.6%) of 31 patients were prescribed SGLT2i over median 101.5 days (37.5-190.8). No patients discontinued SGLT2i use or reported attributable adverse symptoms. No significant differences between patients prescribed SGLT2i compared to those SGLT2i-naïve were seen in: [1] renal function; [2] weight; [3] mean arterial pressure. There were numerically lower infection-related (n = 4 vs 7, HR 0.32 (0.08-1.28), p = 0.11) and haemocompatibility-related (n = 3 vs 4, HR 0.52 (0.09-2.83), p = 0.45) adverse events in the SGLT2i group, albeit non-significant. CONCLUSIONS: We found SGLT2i to be safe and well-tolerated in the BTT LVAD cohort with no significant difference in rates of infection or haemocompatibility-related adverse events with SGLT2i use. Larger studies will inform further beneficial effects of SGLT2i prescription in this cohort.},
	doi = {10.1016/j.ijcard.2023.131259},
	pmid = {37574028 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/ehf2.14339,
	author = {Landra F and Mandoli GE and Sciaccaluga C and Gallone G and Bruno F and Fusi C and Barilli M and Focardi M and Cavigli L and D'Ascenzi F and Bernazzali S and Maccherini M and Cameli M and Valente S},
	title = {Pressure-strain loops unveil haemodynamics behind mechanical circulatory support systems.},
	abstract = {AIMS: Mechanical circulatory support (MCS) systems are increasingly employed in cardiogenic shock and advanced heart failure. A thorough understanding of the complex interactions occurring among heart, vasculature, and device is essential to optimize patient's management. The aim of this study is to explore non-invasive haemodynamic profiling of patients undergoing MCS based on pressure-strain (PS) analysis. METHODS: Clinical and echocardiographic data from consecutive patients undergoing different MCS systems positioning/implantation admitted to the third level cardiological intensive care unit of Siena Hospital from August 2021 to November 2021 were retrospectively reviewed. Patients without a useful echocardiographic exam or without arterial blood pressure recording at the time of echocardiography were excluded. Myocardial work analysis was performed in the included patients. RESULTS: We reviewed 18 patients, of which nine were excluded. Included patients were three patients with intra-aortic balloon pump (IABP), two patients with durable left ventricular assist device (dLVAD), two patients with Impella®, one patient with extracorporeal membrane oxygenation (ECMO), and one patient with ECMO and IABP. Myocardial work analysis was feasible in each included patient. The use of IABP shifted the PS curve rightward and downward. Global work index (GWI) and global wasted work (GWW) decreased after IABP positioning, whereas global work efficiency (GWE) increased. The use of continuous-flow pumps, whether temporaneous (Impella®) or long term (dLVAD), induced a change in the PS loop morphology, with a shift towards a triangular shape. ECMO positioning alone resulted in a narrowing of the PS loop, with a decrease in GWI and GWE and an increase in GWW and mean arterial pressure. The combined used of IABP with ECMO widened the PS loop and improved GWI and GWE. CONCLUSIONS: PS loops analysis in patients undergoing MCS seems to be feasible and may unveil MCS-induced haemodynamic variations. Myocardial work could be used to monitor ventricular-arterial-device coupling and guide tailored MCS management.},
	doi = {10.1002/ehf2.14339},
	pmid = {37345220 [Indexed for MEDLINE]},
	note = {PMC10375099}
}

@ARTICLE{10.1111/aor.14597,
	author = {Mehmood K and Arshad M and Lazoglu I, Küçükaksu DS and Bakuy V},
	title = {In-silico hemodynamic ramp testing of ventricular assist device implanted patients using acausal cardiovascular-VAD modeling.},
	abstract = {BACKGROUND: While cardiovascular system and mechanical circulatory support devices are efficiently model the effect of disease and assistance, they can also lend valuable insights into clinical procedures. This study demonstrates the use of a CVS-VAD model for an invasive procedure; hemodynamic ramp testing, in-silico. METHODS: The CVS model is developed using validated models in literature, using SimscapeTM. An analytically derived pump model is calibrated for the HeartWare VAD. Dilated cardiomyopathy is used as an illustrative example of heart failure, and heart failure patients are created virtually by calibrating the model with requisite disease parameters obtained from published patient data. A clinically applied ramp study protocol is adopted whereby speed optimization is performed following clinically accepted hemodynamic normalization criteria. Trends in hemodynamic variables in response to pump speed increments are obtained. Optimal speed ranges are obtained for the three virtual patients based on target values of central venous pressure (CVP), pulmonary capillary wedge pressure (PCWP), cardiac output (CO), and mean arterial pressure (MAP) for hemodynamic stabilization. RESULTS: Appreciable speed changes in the mild case (300 rpm), slight changes in the moderate case (100 rpm), and no changes in the simulated severe case are possible. CONCLUSION: The study demonstrates a novel application of cardiovascular modeling using an open-source acausal model, which can be potentially beneficial for medical education and research.},
	doi = {10.1111/aor.14597},
	pmid = {37306082 [Indexed for MEDLINE]}
}

@ARTICLE{10.1111/aor.14560,
	author = {Favilla CG and Carter SC and Atluri P and Reehal N and Genuardi MV},
	title = {Noninvasive finger plethysmography for continuous blood pressure monitoring in patients with left ventricular assist device.},
	abstract = {BACKGROUND: Accurate blood pressure (BP) measurement remains challenging in patients with HeartMate 3TM left ventricular assist devices (HM3 LVADs). The Finapres® NOVA is a promising non-invasive continuous BP monitor that uses the volume clamp method via a finger cuff, so here we aimed to validate the instrument in HM3 patients. METHODS: In a single-center cohort, BP was monitored in 15 patients within 72 h following HM3 implantation. A radial artery catheter quantified arterial blood pressure (ABP), while the NOVA measured finger arterial pressure (fiAP) and reconstructed brachial artery pressure (reBAP). Waveforms were recorded for 10 min, and mean values were calculated in 15-s intervals. RESUTS: fiAP and ABP were moderately correlated during both the first (ICC 0.61, p = 0.04) and final measurements (ICC 0.66, p = 0.03). reBAP and ABP were strongly correlated during both the first (ICC 0.81, p = 0.002) and final measurements (ICC 0.83, p = 0.001). Both NOVA-derived values may underestimate low BP values while overestimating relatively high BP values. The reBAP was within 5 mm Hg of the ABP in 40% of patients (and within 10 mm Hg in 67%). CONCLUSIONS: This pilot represents the first evidence in support of the Finapres® NOVA for non-invasive BP measurement in select patients with HM3 LVADs. The instrument may provide useful data during BP medication adjustments or pump titration, but despite the correlation between the non-invasive reBAP and invasive ABP, individual-level inaccuracy may be clinically meaningful. Further investigation is needed to clarify these limitations and optimize accuracy before widespread adoption in this unique patient population.},
	doi = {10.1111/aor.14560},
	pmid = {37150940 [Indexed for MEDLINE]},
	note = {PMC12884544}
}

@ARTICLE{10.1177/03913988231168159,
	author = {Nagy P and Sax B, Kozák A and Merkely B and Osztheimer I, Jobbágy Á},
	title = {Automatic non-invasive blood pressure measurement in left ventricular assist device patients with a photoplethysmography assisted device.},
	journal = {Int J Artif Organs},
	year = {2023},
	abstract = {INTRODUCTION: Non-invasive measurement of blood pressure in patients with a left ventricular assist device (LVAD) is challenging due to the mechanical properties of these circulatory support devices. Keeping blood pressure in a target range is crucial to reduce the risk of LVAD complications. As current assessment methods require trained personnel resulting in infrequent monitoring, devices for home-based measurements are sorely needed. OBJECTIVES: In this paper, we report a measurement method and a custom-made monitoring device based on photoplethysmography (PPG) enabling automated measurement of the mean arterial pressure (MAP) of patients with LVAD. METHODS: The method and the device were tested on 21 adult patients with LVAD, and the estimated MAP values were compared to MAP values measured simultaneously by a human expert applying the commonly used Doppler-based method. RESULTS: Results of the proposed method showed highly significant correlation with Doppler-based MAP values (R = 0.85 for inflation, p < 0.001; R = 0.96 for deflation, p<0.001). The mean difference of the proposed method to the Doppler-based MAP values was 1.48 ± 5.43 mmHg for inflation and -0.19 ± 2.71 mmHg for deflation. CONCLUSION: The results demonstrate that the proposed method is a promising direction to achieve accurate, automated, non-invasive BP measurement, applicable in home health monitoring for patients with LVAD.},
	doi = {10.1177/03913988231168159},
	pmid = {37051689 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fcvm.2023.1140153,
	author = {De Potter T and Valeriano C and Buytaert D and Bouchez S and Ector J},
	title = {Noninvasive neurological monitoring to enhance pLVAD-assisted ventricular tachycardia ablation - a Mini review.},
	journal = {Front Cardiovasc Med},
	year = {2023},
	abstract = {For critically ill patients, hemodynamic fluctuations can be life-threatening; this is particularly true for patients experiencing cardiac comorbidities. Patients may suffer from problems with heart contractility and rate, vascular tone, and intravascular volume, resulting in hemodynamic instability. Unsurprisingly, hemodynamic support provides a crucial and specific benefit during percutaneous ablation of ventricular tachycardia (VT). Mapping, understanding, and treating the arrhythmia during sustained VT without hemodynamic support is often infeasible due to patient hemodynamic collapse. Substrate mapping in sinus rhythm can be successful for VT ablation, but there are limitations to this approach. Patients with nonischemic cardiomyopathy may present for ablation without exhibiting useful endocardial and/or epicardial substrate-based ablation targets, either due to diffuse extent or a lack of identifiable substrate. This leaves activation mapping during ongoing VT as the only viable diagnostic strategy. By enhancing cardiac output, percutaneous left ventricular assist devices (pLVAD) may facilitate conditions for mapping that would otherwise be incompatible with survival. However, the optimal mean arterial pressure to maintain end-organ perfusion in presence of nonpulsatile flow remains unknown. Near infrared oxygenation monitoring during pLVAD support provides assessment of critical end-organ perfusion during VT, enabling successful mapping and ablation with the continual assurance of adequate brain oxygenation. This focused review provides practical use case scenarios for such an approach, which aims to allow mapping and ablation of ongoing VT while drastically reducing the risk of ischemic brain injury.},
	doi = {10.3389/fcvm.2023.1140153},
	pmid = {36970357},
	note = {PMC10031079}
}

@ARTICLE{10.1016/j.cardfail.2023.01.009,
	author = {Trachtenberg B and Cowger J and Jennings DL and Grafton G and Loyaga-Rendon R and Cogswell R and Klein L and Shah P and Kiernan M and Vorovich E},
	title = {HFSA Expert Consensus Statement on the Medical Management of Patients on Durable Mechanical Circulatory Support.},
