@ARTICLE{10.1109/EMBC48229.2022.9871694,
	author = {Kataoka Y and Fukuda Y and Peterson J and Shelly I and Alexander J and Sunagawa K},
	title = {System Design for Optimizing Drug Infusions Using Cardiovascular Space Mapping for Acute Heart Failure.},
	journal = {Annu Int Conf IEEE Eng Med Biol Soc},
	year = {2022},
	abstract = {Acute heart failure is caused by various factors and requires multiple drug therapies to remedy underlying causes. Due to the complexity of pharmacologic effects of cardiovascular agents, few studies have theoretically addressed the multidrug optimization problem. This paper proposes a drug infusion system for acute heart failure that controls cardiovascular performance metrics (cardiac output, left atrial pressure, and mean arterial pressure) within desired ranges as dictated by the cardiovascular parameters (systemic vascular resistance, cardiac contractility, heart rate, and stressed blood volume). The key to our system design is modeling and controlling cardiovascular parameters to yield the desired cardiovascular metrics. A 'tailored drug infusion' technique controls parameters by solving the optimization problem in order to conquer the complexity of multi-dependencies and the different dosage limits among multiple drugs. A 'cardiovascular space mapping' technique identifies the desired parameters from the desired metrics by deriving the analytical solutions of the metrics as functions of the parameters. To facilitate clinical discussions, parameters were set to realistic values in 5,600 simulated patients. Our results showed not only that the optimized drug combinations and dosages controlled the cardiovascular metrics to within the desired ranges, but also that they mostly corresponded to the recommended clinical use guidelines. An additional value of our system is that it proactively predicts the limitations of the tailored drug therapy, which supports the clinical decision of pivoting to alternative treatment strategies such as mechanical circulatory support.},
	doi = {10.1109/EMBC48229.2022.9871694},
	pmid = {36086004 [Indexed for MEDLINE]}
}

@ARTICLE{10.1111/aor.14367,
	author = {Lankheet S and Pieterse MM and Rijnhout R and Tuerlings E and Oppelaar AC, van Laake LW and Ramjankhan FZ and Westerhof BE and Oerlemans MIFJ},
	title = {Validity and success rate of noninvasive mean arterial blood pressure measurements in cf-LVAD patients: A technical review.},
	abstract = {BACKGROUND: The life expectancy of patients with a continuous flow left ventricular assist device (cf-LVAD) is increasing. Adequate determination and regulation of mean arterial pressure (MAP) is important to prevent adverse events. Given the low pulsatility characteristics in these patients, standard blood pressure equipment is inadequate to monitor MAP and not recommended. We provide an overview of currently available noninvasive techniques, using an extensive search strategy in three online databases (Pubmed, Scopus and Google Scholar) to find validation studies using invasive intra-arterial blood pressure measurement as a reference. Mean differences with the reference values smaller than 5 ± 8 mm Hg were considered acceptable. OBSERVATIONS: After deduplication, screening, and exclusion of incorrect sources, eleven studies remained with 3139 successful MAP measurements in 386 patients. Four noninvasive techniques, using Doppler, pulse oximetry, finger cuff volume clamp, or slow upper arm cuff deflation, were identified and evaluated for validity and success rate in cf-LVAD patients. Here, a comprehensive technical background of the blood pressure measurement methods is provided in combination with a clinical use comparison. Of the reported noninvasive techniques, slow cuff devices performed most optimally (mean difference 1.3 ± 5.2 mm Hg). CONCLUSIONS: Our results are encouraging and indicate that noninvasive blood pressure monitoring options with acceptable validity and success rate are available. Further technical development and validation is warranted for the growing population of patients on long-term cf-LVAD support.},
	doi = {10.1111/aor.14367},
	pmid = {35920238 [Indexed for MEDLINE]},
	note = {PMC9804858}
}

@ARTICLE{10.1007/s10047-022-01349-w,
	author = {Tanaka A and Kiriyama Y and Kubo N and Sakaguchi R and Uchiyama A and Fujino Y},
	title = {Noninvasive blood pressure measurement in patients with continuous-flow left ventricular assist devices.},
	journal = {J Artif Organs},
	year = {2023},
	abstract = {Oscillatory blood pressure (OBP) with a slow cuff-deflation system has been proposed as noninvasive measurement of mean arterial pressure (MAP) in patients with continuous-flow left ventricular assist devices (LVADs). However, the challenge is that the measurement is not obtainable in certain patients. We hypothesized that the combined use of color Doppler imaging during OBP measurement (CDBP) could derive MAP accurately. We conducted a prospective observational study in critically ill patients (30 patients with continuous-flow LVADs and 30 control patients without LVADs). Triplicate OBP and CDBP measurements were performed and invasive blood pressure (IBP) was recorded. The overall success rate of OBP was 63.3% in the LVAD group and 98.9% in the control group. The CDBP was successfully obtained in 100% of all study patients. The CDBP in the LVAD group was closest to the MAP of measured IBP, while that in the control group was closest to the systolic IBP. The mean absolute differences in OBP and CDBP from the closest IBP were similar in both the control and LVAD groups. In nonpulsatile LVAD patients with a pulse pressure IBP < 10 mmHg, the success rate of OBP measurement was only 10.0%, and CDBP showed significantly reduced error in MAP measurement (mean absolute difference: OBP 23.2 ± 8.7 vs CDBP 5.2 ± 3.6 mmHg, p < 0.001). The validity of OBP measurement with a slow cuff-deflation system limited particularly in nonpulsatile LVAD patients. The concurrent use of color Doppler imaging is encouraged for more accurate measurement of MAP in patients with continuous-flow LVADs.},
	doi = {10.1007/s10047-022-01349-w},
	pmid = {35907151 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.resplu.2022.100254,
	author = {Akhtar W and Gamble B and Kiff K and Wypych-Zych A and Raj B and Takata J and Gil FR and Hurtado A and Rosenberg A and Bowles CT},
	title = {Mechanical life support algorithm developed by simulation for inpatient emergency management of recipients of implantable left ventricular assist devices.},
	journal = {Resusc Plus},
	year = {2022},
	abstract = {BACKGROUND: Published guidance concerning emergency management of left ventricular assist device (LVAD) recipients is both limited and lacking in consensus which increases the risk of delayed and/or inappropriate actions. METHODS: In our specialist tertiary referral centre we developed, by iteration, a novel in-hospital resuscitation algorithm for LVAD emergencies which we validated through simulation and assessment of our multi-disciplinary team. A Mechanical Life Support course was established to provide theoretical and practical education combined with simulation to consolidate knowledge and confidence in algorithm use. We assessed these measures using confidence scoring, a key performance indicator (the time taken to restart LVAD function) and a multiple-choice question (MCQ) examination. RESULTS: The mean baseline staff confidence score in management of LVAD emergencies was 2.4 ± 1.2 out of a maximum of 5 (n = 29). After training with simulation, mean confidence score increased to 3.5 ± 0.8 (n = 13).Clinical personnel who were provided with the novel resuscitation algorithm were able to reduce time taken to restart LVAD function from a mean value of 49 ± 8.2 seconds (pre-training) to 20.4 ± 5 seconds (post-training) (n = 42, p < 0.0001).The Mechanical Life Support course increased mean confidence from 2.5 ± 1.2 to 4 ± 0.6 (n = 44, p < 0.0001) and mean MCQ score from 18.7 ± 3.4 to 22.8 ± 2.6, out of a maximum of 28 (n = 44, p < 0.0001). CONCLUSION: We present a simplified LVAD Advanced Life Support algorithm to aid the crucial first minutes of resuscitation where basic interventions are likely to be critical in assuring good patient outcomes.},
	doi = {10.1016/j.resplu.2022.100254},
	pmid = {35669526},
	note = {PMC9162943}
}

@ARTICLE{10.3390/jcm11092567,
	author = {Szczurek-Wasilewicz W and Skrzypek M and Romuk E, Gąsior M, Szyguła-Jurkiewicz B},
	title = {The Utility of Pentraxin and Modified Prognostic Scales in Predicting Outcomes of Patients with End-Stage Heart Failure.},
	journal = {J Clin Med},
	year = {2022},
	abstract = {Risk stratification is an important element of management in patients with heart failure (HF). We aimed to determine factors associated with predicting outcomes in end-stage HF patients listed for heart transplantation (HT), with particular emphasis placed on pentraxin-3 (PXT-3). In addition, we investigated whether the combination of PTX-3 with the Heart Failure Survival Score (HFSS), the Seattle Heart Failure Model (SHFM), or the Meta-Analysis Global Group in Chronic Heart Failure (MAGGIC) improved the prognostic strength of these scales in the study population. We conducted a prospective analysis of 343 outpatients with end-stage HF who accepted the HT waiting list between 2015 and 2018. HFSS, SHFM, and MAGGIC scores were calculated for all patients. PTX3 was measured by sandwich enzyme-linked immunosorbent assay with a commercially available kit. The endpoints were death, left ventricular assist device implantation, and HT during the one-year follow-up. The median age was 56 (50−60) years, and 86.6% were male. During the follow-up period, 173 patients reached the endpoint. Independent risk factors associated with outcomes were ischemic etiology of HF [HR 1.731 (1.227−2.441), p = 0.0018], mean arterial pressure (MAP) [1.026 (1.010−1.042), p = 0.0011], body mass index (BMI) [1.055 (1.014−1.098), p = 0.0083], sodium [1.056 [(1.007−1.109), p = 0.0244] PTX-3 [1.187 (1.126−1.251, p < 0.0001) and N-terminal pro-brain natriuretic peptide (NT-proBNP) [HR 1.004 (1.000−1.008), p = 0.0259]. The HFSS-PTX-3, SHFM-PTX-3 and MAGGIC-PTX-3 scores had significantly higher predictive power [AUC = 0.951, AUC = 0.973; AUC = 0.956, respectively] than original scores [AUC for HFSS = 0.8481, AUC for SHFM = 0.7976, AUC for MAGGIC = 0.7491]. Higher PTX-3 and NT-proBNP concentrations, lower sodium concentrations, lower MAP and BMI levels, and ischemic etiology of HF are associated with worse outcomes in patients with end-stage HF. The modified SHFM-PTX-3, HFSS-PTX-3, and MAGGIC-PTX-3 scores provide effective methods of assessing the outcomes in the analyzed group.},
	doi = {10.3390/jcm11092567},
	pmid = {35566693},
	note = {PMC9099900}
}

@ARTICLE{10.1007/s10237-022-01585-2,
	author = {Gil A and Navarro R and Quintero P and Mares A, Pérez M and Montero JA},
	title = {CFD analysis of the HVAD's hemodynamic performance and blood damage with insight into gap clearance.},
	journal = {Biomech Model Mechanobiol},
	year = {2022},
	abstract = {Mechanical circulatory support using ventricular assist devices has become commonplace in the treatment of patients suffering from advanced stages of heart failure. While blood damage generated by these devices has been evaluated in depth, their hemodynamic performance has been investigated much less. This work presents the analysis of the complete operating map of a left ventricular assist device, in terms of pressure head, power and efficiency. Further investigation into its hemocompatibility is included as well. To achieve these objectives, computational fluid dynamics simulations of a centrifugal blood pump with a wide-blade impeller were performed. Several conditions were considered by varying the rotational speed and volumetric flow rate. Regarding the device's hemocompatibility, blood damage was evaluated by means of the hemolysis index. By relating the hemocompatibility of the device to its hemodynamic performance, the results have demonstrated that the highest hemolysis occurs at low flow rates, corresponding to operating conditions of low efficiency. Both performance and hemocompatibility are affected by the gap clearance. An innovative investigation into the influence of this design parameter has yielded decreased efficiencies and increased hemolysis as the gap clearance is reduced. As a further novelty, pump operating maps were non-dimensionalized to highlight the influence of Reynolds number, which allows their application to any working condition. The pump's operating range places it in the transitional regime between laminar and turbulent, leading to enhanced efficiency for the highest Reynolds number.},
	doi = {10.1007/s10237-022-01585-2},
	pmid = {35546646 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.jaccas.2022.01.019,
	author = {Jain P and Kiernan MS and Couper GS and Brovman EY and Asber SR and Kimmelstiel C},
	title = {Percutaneous Decommissioning of a Left Ventricular Assist Device in a Patient With Myocardial Recovery.},
